-- Categories
INSERT INTO categories (id, slug, name, description, icon, image_url, intro, buying_criteria, related_slugs, seo_title, seo_description, hero_angle, sort_order, archived_at, created_at, updated_at) VALUES ('cat-1', 'crm', 'CRM', 'Relationship ledgers for private capital. Track every conversation, intro, and follow-up across the firm’s deal flow.', '🤝', '/images/categories/crm.jpg', NULL, NULL, NULL, NULL, NULL, NULL, 0, NULL, 1777150116019, 1777150116019), ('cat-2', 'data', 'Data', 'Market databases, company graphs, and private-market intelligence. The raw material behind every investment memo.', '📈', '/images/categories/data.jpg', NULL, NULL, NULL, NULL, NULL, NULL, 1, NULL, 1777150116019, 1777150116019), ('cat-3', 'research', 'Research', 'Primary and secondary research workbenches. Expert calls, sector scans, and the long read behind a short decision.', '🔬', '/images/categories/research.jpg', NULL, NULL, NULL, NULL, NULL, NULL, 2, NULL, 1777150116019, 1777150116019), ('cat-4', 'news', 'News', 'The daily broadsheet of venture. Feeds, aggregators, and newsletters investors read before the first coffee.', '📰', '/images/categories/news-resources.jpg', NULL, NULL, NULL, NULL, NULL, NULL, 3, NULL, 1777150116019, 1777150116019), ('cat-5', 'ai', 'AI', 'General-purpose copilots and assistants. The cognitive layer sitting under every other workflow on this page.', '✨', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 4, NULL, 1777150116019, 1777150116019), ('cat-6', 'portfolio-management', 'Portfolio Management', 'Where a fund watches what it already owns. Metrics, KPIs, and quarterly letters for the companies on the cap table.', '📊', '/images/categories/portfolio-management.jpg', NULL, NULL, NULL, NULL, NULL, NULL, 5, NULL, 1777150116019, 1777150116019), ('cat-9', 'admin-ops', 'Admin & Ops', 'Fund administration, compliance, and the operational scaffolding behind running a venture firm.', '⚙️', '/images/categories/infrastructure.jpg', NULL, NULL, NULL, NULL, NULL, NULL, 6, NULL, 1777150116019, 1777150116019), ('cat-10', 'automation', 'Automation', 'Workflow glue. No-code engines that wire your CRM, inbox, and data room together without a developer.', '🔁', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 7, NULL, 1777150116019, 1777150116019), ('cat-11', 'communication', 'Communication', 'Where the partnership talks to itself and the outside world. Chat, video, and the rooms where diligence happens.', '💬', '/images/categories/video-conferencing.jpg', NULL, NULL, NULL, NULL, NULL, NULL, 8, NULL, 1777150116019, 1777150116019), ('cat-12', 'mailing', 'Mailing', 'Inbox infrastructure. From founder LPs mail to quarterly newsletters, this is where correspondence is sent and filed.', '📧', '/images/categories/email.jpg', NULL, NULL, NULL, NULL, NULL, NULL, 9, NULL, 1777150116019, 1777150116019), ('cat-13', 'calendar', 'Calendar', 'Booking, blocking, and defending time. Tools that decide when the partnership meets and when the founder gets ten minutes.', '📅', '/images/categories/calendar.jpg', NULL, NULL, NULL, NULL, NULL, NULL, 10, NULL, 1777150116019, 1777150116019), ('cat-14', 'transcription', 'Transcription', 'Meeting recorders and note-takers. Every call, pitch, and partner meeting turned into searchable text.', '📝', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 11, NULL, 1777150116019, 1777150116019), ('cat-15', 'voice-to-text', 'Voice to Text', 'Dictation for the investor on the move. Turn voice memos between meetings into memos in the CRM.', '🎙️', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 12, NULL, 1777150116019, 1777150116019), ('cat-16', 'productivity', 'Productivity', 'Docs, wikis, and task boards. The second brain where theses, diligence, and portfolio notes all live.', '🗂️', '/images/categories/project-management.jpg', NULL, NULL, NULL, NULL, NULL, NULL, 13, NULL, 1777150116019, 1777150116019), ('cat-17', 'vibe-coding', 'Vibe Coding', 'AI-native builders for non-engineers. Prototype a landing page, a dashboard, or a diligence tool before lunch.', '🛠️', '/images/categories/platform.jpg', NULL, NULL, NULL, NULL, NULL, NULL, 14, NULL, 1777150116019, 1777150116019), ('cat-18', 'browser', 'Browser', 'The window to the work. Investor-grade browsers with tabs, workspaces, and AI built into the address bar.', '🌐', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 15, NULL, 1777150116019, 1777150116019), ('cat-19', 'other-tools', 'Other Tools', 'Everything else on the investor’s desktop. Design files, storage, shortcuts, and the utilities that refuse a tidier shelf.', '🔧', '/images/categories/other-tools.jpg', NULL, NULL, NULL, NULL, NULL, NULL, 16, NULL, 1777150116019, 1777150116019) ON CONFLICT(id) DO UPDATE SET slug = excluded.slug, name = excluded.name, description = excluded.description, icon = excluded.icon, image_url = excluded.image_url, intro = excluded.intro, buying_criteria = excluded.buying_criteria, related_slugs = excluded.related_slugs, seo_title = excluded.seo_title, seo_description = excluded.seo_description, hero_angle = excluded.hero_angle, sort_order = excluded.sort_order, archived_at = excluded.archived_at, updated_at = excluded.updated_at;

-- Tools
INSERT INTO tools (id, slug, name, description, short_desc, use_cases, website_url, logo_url, pricing_model, is_featured, featured_order, category_id, extra_category_slugs, archived_at, created_at, updated_at) VALUES ('t-1', 'affinity', 'Affinity', 'Affinity is a relationship-intelligence CRM built for private markets. It auto-captures the network graph by reading Gmail, Outlook, and calendar activity in the background, so pipeline stays current without manual logging. It scores relationship strength and surfaces the warmest path to any contact. Widely used by VC firms to manage dealflow and find intros to founders.', 'Relationship-intelligence CRM that reads your inbox to map dealflow', '["Track dealflow from first meeting to term sheet without manual CRM entry","Find the warmest internal path to a founder before sending a cold email"]', 'https://affinity.co', 'https://www.google.com/s2/favicons?domain=affinity.co&sz=128', 'PAID', 0, NULL, 'cat-1', NULL, NULL, 1777150116019, 1777150116019), ('t-2', 'airtable', 'Airtable', 'Airtable is a relational database with a spreadsheet-like interface, plus views, forms, and automations on top of every table. Non-technical users build custom trackers without writing SQL, and records connect across tables like a lightweight app. Widely used by VC firms as a lightweight dealflow tracker, portfolio database, or LP list before graduating to a dedicated CRM.', 'Flexible relational database that behaves like a spreadsheet', '["Build a dealflow tracker with custom stages, owners, and scoring in an afternoon","Keep a shared portfolio database with founder contacts, board dates, and KPIs"]', 'https://airtable.com', 'https://www.google.com/s2/favicons?domain=airtable.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-1', '["productivity"]', NULL, 1777150116019, 1777150116019), ('t-3', 'asana', 'Asana', 'Asana is a work management platform that organises projects, tasks, and goals across a team in shared views like lists, boards, timelines, and Gantt. Automations and AI teammates handle status updates, request intake, and routine follow-ups. Used by VC firms to run platform team projects, fundraising workstreams, and portfolio support programs with clear ownership and deadlines.', 'Work management platform for tracking projects, tasks, and goals', '["Run a fundraising workstream with LP outreach tracked by stage and owner","Coordinate portfolio support programs across platform, talent, and marketing teams with clear ownership and deadlines"]', 'https://asana.com', 'https://www.google.com/s2/favicons?domain=asana.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-1', NULL, NULL, 1777150116019, 1777150116019), ('t-4', 'attio', 'Attio', 'Attio is an AI-native CRM built around a fully customisable data model, with email and calendar sync, contact enrichment, and semantic search across meetings and threads. No-code automations and reports make it adaptable to any pipeline shape. Increasingly used by VC firms as a lighter, more modern alternative to Affinity for tracking dealflow, relationships, and portfolio contacts.', 'AI-native CRM with a flexible data model and semantic search', '["Shape a custom dealflow pipeline with investor-specific fields, stages, and automated enrichment on every new record","Search every past meeting and email for context on a founder before a call"]', 'https://attio.com', 'https://www.google.com/s2/favicons?domain=attio.com&sz=128', 'PAID', 1, NULL, 'cat-1', NULL, NULL, 1777150116019, 1777150116019), ('t-5', 'clay', 'Clay', 'Clay pulls from 150+ data providers in a waterfall to enrich any list of companies or people, then layers AI research agents and buying-intent signals on top. Teams build audiences, write outreach, and push to CRMs from one spreadsheet-like surface. Used by VC firms to build founder lists, enrich dealflow with funding and headcount data, and automate sourcing outreach.', 'Data enrichment and AI research for targeted outbound at scale', '["Build a ranked list of seed-stage founders by role, headcount growth, and recent funding","Enrich inbound deal submissions with team backgrounds, competitive landscape, and funding history before they reach an investor"]', 'https://clay.com', 'https://www.google.com/s2/favicons?domain=clay.com&sz=128', 'PAID', 0, NULL, 'cat-1', NULL, NULL, 1777150116019, 1777150116019), ('t-6', 'evertrace', 'EverTrace', 'A founder-detection engine that flags builders before they appear in conventional startup databases. It watches signals across LinkedIn, GitHub, X co-founder search posts, trade registries, domain registrations, patents, research papers, and hackathon wins, then routes matches into Affinity, Attio, HubSpot, or Salesforce. Used by early-stage VCs to reach stealth founders weeks or months ahead of competing funds.', 'Stealth-founder detection from LinkedIn, GitHub, X, and registry signals', '["Surface stealth founders from LinkedIn, GitHub, and X signals before they list a company","Pipe real-time incorporation and domain alerts into Affinity or Attio for same-day outreach"]', 'https://evertrace.ai', 'https://www.google.com/s2/favicons?domain=evertrace.ai&sz=128', 'PAID', 1, NULL, 'cat-2', NULL, NULL, 1777150116019, 1777150116019), ('t-7', 'folk', 'Folk', 'Folk is a modern, lightweight CRM focused on relationship management rather than heavy sales pipeline. Its folkX browser extension captures contacts from LinkedIn, Gmail, and Outlook in one click, and AI assistants handle follow-ups, recaps, and enrichment. Used by smaller VC firms, angels, and scouts to track founder conversations and investor networks without the overhead of an enterprise CRM.', 'Lightweight CRM that pulls contacts from LinkedIn, Gmail, and WhatsApp', '["Capture founders and co-investors from LinkedIn into a shared CRM in seconds","Run personalised investor updates or founder outreach off a segmented contact list enriched from LinkedIn"]', 'https://folk.app', 'https://www.google.com/s2/favicons?domain=folk.app&sz=128', 'FREEMIUM', 0, NULL, 'cat-1', NULL, NULL, 1777150116019, 1777150116019), ('t-8', 'hubspot', 'HubSpot', 'HubSpot bundles CRM, marketing automation, sales pipeline, service desk, and content tools into one customer platform, with Breeze AI agents for prospecting, support, and data cleanup on top. Strongest on the inbound-and-outreach side where most tools stop at CRM. Used by VC firms that run heavy content, newsletter, or LP marketing motions and want attribution back to the source.', 'Full CRM and marketing suite for firms that run outbound and content', '["Run LP and founder newsletters with full open, click, and attribution tracking","Manage inbound deal submissions through a standard CRM pipeline with automated routing"]', 'https://hubspot.com', 'https://www.google.com/s2/favicons?domain=hubspot.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-1', NULL, NULL, 1777150116019, 1777150116019), ('t-9', 'notion', 'Notion', 'Notion is a unified workspace where docs, wikis, databases, and projects live in the same flexible surface. Custom agents now handle search, reporting, and routing across the workspace, and recent launches add Mail and Calendar. Used by VC firms as the internal wiki, IC memo repository, and shared database for deal notes, portfolio tracking, and fund playbooks.', 'AI workspace combining docs, databases, and agents in one surface', '["Host IC memos, deal notes, and founder updates in one searchable knowledge base","Run a lightweight dealflow tracker as a database with linked memo pages"]', 'https://notion.so', 'https://www.google.com/s2/favicons?domain=notion.so&sz=128', 'FREEMIUM', 0, NULL, 'cat-1', '["productivity","transcription"]', NULL, 1777150116019, 1777150116019), ('t-11', 'streak', 'Streak', 'Streak turns Gmail itself into a CRM, with pipelines, stages, and shared deal views rendered alongside the inbox. Email tracking, mail merge, and AI-powered columns automate logging and follow-ups without forcing a context switch. Popular with solo GPs and smaller VC firms who already run dealflow and LP conversations out of Gmail and want a CRM layer without leaving it.', 'CRM built directly inside Gmail for teams that live in the inbox', '["Track every founder email thread against a deal stage without leaving Gmail","Send personalised LP updates via mail merge with per-recipient open and click tracking directly from Gmail"]', 'https://streak.com', 'https://www.google.com/s2/favicons?domain=streak.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-1', NULL, NULL, 1777150116019, 1777150116019), ('t-12', 'taghash', 'Taghash', 'Taghash is an integrated fund operating system that stitches dealflow, portfolio tracking, fund accounting, and LP reporting into one platform. Deals pull in from email, WhatsApp, and forms, while the portfolio module handles cap tables, valuations, and IRR, DPI, and MOIC metrics. Popular with Indian VC firms including Kalaari and Blume Ventures that want a single system instead of stitching five tools together.', 'All-in-one fund operating system covering dealflow, portfolio, and LPs', '["Consolidate dealflow from WhatsApp, email, and web forms into one triage queue","Generate quarterly LP reports with IRR, DPI, and MOIC directly from portfolio data"]', 'https://taghash.io', 'https://www.google.com/s2/favicons?domain=taghash.io&sz=128', 'PAID', 1, NULL, 'cat-1', '["portfolio-management"]', NULL, 1777150116019, 1777150116019), ('t-13', 'cb-insights', 'CB Insights', 'A private-market intelligence platform covering 11 million companies and 1,600+ markets, with funding histories, hiring patterns, and Mosaic health scores. Strategy maps visualise competitive activity, and AI agents generate target lists, scouting reports, and memos. Used by VC and corporate venture teams to size emerging categories, track category leaders, and build diligence context before a first call.', 'Predictive intelligence on private companies, markets, and competitive activity', '["Build a market map of an emerging sector with funding, hiring, and Mosaic health scores","Pull comparable deals and category benchmarks to frame an investment committee memo"]', 'https://cbinsights.com', 'https://www.google.com/s2/favicons?domain=cbinsights.com&sz=128', 'ENTERPRISE', 1, NULL, 'cat-2', NULL, NULL, 1777150116019, 1777150116019), ('t-14', 'crunchbase', 'Crunchbase', 'The widely referenced private-market database, tracking funding rounds, founders, acquirers, and exits across global startups. Predictive signals flag companies likely to raise next, and the Pro tier exposes advanced filters, saved searches, and API access. Used by VCs for quick founder lookups, competitive scans, round timing, and as the baseline source for pipeline enrichment in CRMs like Affinity and Attio.', 'Public-facing private market database for funding rounds, companies, and exits', '["Check a founder''s prior funding history and co-investors before a first partner meeting","Filter by sector, stage, and last-round date to build a weekly outreach list"]', 'https://crunchbase.com', 'https://www.google.com/s2/favicons?domain=crunchbase.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-2', NULL, NULL, 1777150116019, 1777150116019), ('t-15', 'harmonic', 'Harmonic', 'A discovery platform covering 30 million companies and 190 million people, tuned for catching startups at formation. Filters span funding, headcount, and growth metrics; the Scout agent takes natural-language briefs and returns research reports and market maps. Network mapping syncs email, calendar, and LinkedIn so VCs can spot warm intro paths and talent movement the moment a founder goes independent.', 'Early-stage startup and founder discovery engine with AI research agents', '["Track senior operators leaving top companies and trigger alerts when they start a new entity","Generate a Scout market map on an emerging thesis and auto-draft outreach to matching founders"]', 'https://harmonic.ai', 'https://www.google.com/s2/favicons?domain=harmonic.ai&sz=128', 'PAID', 1, NULL, 'cat-2', NULL, NULL, 1777150116019, 1777150116019), ('t-16', 'inc42-data-labs', 'Inc42 Data Labs', 'Inc42''s intelligence arm covers 75,000+ Indian startups, 3,000+ investors, and 20,000+ funding rounds, blending Inc42 reporting with MCA filings and 200+ proprietary feeds. Signal Feed pushes funding, regulatory, and talent alerts over email and WhatsApp within 24 hours. Used by India-focused VCs to build sector theses, track competitors, and export company snapshots straight into investment memos.', 'India startup intelligence platform with MCA data, signals, and company profiles', '["Track MCA filings and valuation trajectories of shortlisted Indian startups across a sector thesis","Subscribe to Signal Feed alerts on funding rounds and talent moves for weekly pipeline review"]', 'https://inc42.com', 'https://www.google.com/s2/favicons?domain=inc42.com&sz=128', 'PAID', 0, NULL, 'cat-2', NULL, NULL, 1777150116019, 1777150116019), ('t-17', 'linkedin-sales-nav', 'LinkedIn Sales Nav', 'LinkedIn''s premium sourcing surface, with fifty-plus filters across function, seniority, tenure, and geography over a billion profiles. InMail credits unlock direct messaging, TeamLink surfaces warm paths through colleague networks, and Account and Lead IQ generate AI briefings on prospects. Used by VCs to build founder longlists, map portfolio hiring targets, and identify the shortest intro path before cold outreach.', 'LinkedIn''s advanced search, InMail, and warm-intro engine over a billion users', '["Build a filtered list of ex-FAANG founders in a target sector and trigger TeamLink warm intros","Map a portfolio company''s hiring targets and draft Account IQ briefs before outreach"]', 'https://linkedin.com', 'https://www.google.com/s2/favicons?domain=linkedin.com&sz=128', 'PAID', 0, NULL, 'cat-2', NULL, NULL, 1777150116019, 1777150116019), ('t-18', 'pitchbook', 'PitchBook', 'The institutional reference for private-market data, with deep coverage of VC, PE, M&A, and public markets across companies, funds, and LPs. Profiles carry round-by-round cap tables, valuations, comparables, and fund-level IRR benchmarks. Used by VC firms for competitive benchmarking, diligence on co-investors, LP research ahead of fundraising, and pulling comparable-deal valuations into investment memos.', 'Institutional private-market data spanning VC, PE, M&A, and fund performance', '["Pull round history, cap table, and valuation comps for a target before an IC memo","Benchmark a fund''s pace and TVPI against peer vintages during LP fundraising prep"]', 'https://pitchbook.com', 'https://www.google.com/s2/favicons?domain=pitchbook.com&sz=128', 'ENTERPRISE', 1, NULL, 'cat-2', NULL, NULL, 1777150116019, 1777150116019), ('t-19', 'preqin', 'Preqin', 'Preqin Pro covers eight alternative-asset classes, including VC, PE, hedge funds, private debt, real estate, and infrastructure. Data runs across funds, managers, deals, and institutional LPs, with benchmarks for IRR, TVPI, and fund terms. Used by GPs to identify and prioritise LPs for the next fundraise, and by LPs to screen managers, run due diligence, and benchmark returns against peer vintages.', 'Alternative-assets data for fund performance, LP mapping, and manager selection', '["Build a ranked LP target list by asset-class appetite and historic ticket size before fundraising","Benchmark a fund''s IRR and DPI against peer vintage and geography during LP reporting"]', 'https://preqin.com', 'https://www.google.com/s2/favicons?domain=preqin.com&sz=128', 'ENTERPRISE', 0, NULL, 'cat-2', NULL, NULL, 1777150116019, 1777150116019), ('t-20', 'private-circle', 'Private Circle', 'An India-focused research database on 2.6 million unlisted companies, built from MCA filings, triangulated financials, and compliance records. Screeners cover income statements, balance sheets, valuations, cap tables, and legal cases, with web and app-traffic signals layered in. Used by VC, PE, and IB teams for diligence on Indian targets, competitor benchmarking, and screening for founders with strong underlying financial signals.', 'India private-company intelligence built on MCA filings and triangulated data', '["Pull three-year financials and shareholding from MCA filings for diligence on an Indian target","Screen Indian companies by revenue, margin, and cap-table shape to build a thematic longlist"]', 'https://privatecircle.co', 'https://www.google.com/s2/favicons?domain=privatecircle.co&sz=128', 'PAID', 0, NULL, 'cat-2', NULL, NULL, 1777150116019, 1777150116019), ('t-22', 'sanchi-connect', 'Sanchi Connect', 'India''s dedicated deeptech enablement network, connecting startups working on AI, robotics, quantum, biotech, and semiconductors with 470+ investors, 150+ mentors, and 50+ corporate partners. SanchiSaaS handles incubation workflows, while PowerPitch and Live Pitch run video pitches and application reviews. Used by deeptech VCs for curated dealflow and by corporates for POC partnerships with vetted Indian research-led teams.', 'India deeptech network linking founders with investors, mentors, and corporates', '["Source pre-vetted Indian deeptech startups by sector and pitch stage for a quarterly review","Run corporate innovation POCs with deeptech founders matched through the Sanchi network"]', 'https://sanchiconnect.com', 'https://www.google.com/s2/favicons?domain=sanchiconnect.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-2', NULL, NULL, 1777150116019, 1777150116019), ('t-23', 'tracxn', 'Tracxn', 'A global startup database with 7.1 million companies, 55,000+ sector taxonomies, and human-curated market maps. Daily deal feeds cover funded and unfunded companies across 30+ countries, with financials, cap tables, and acquisition histories. Used by VCs for dealflow discovery in niche categories, competitive benchmarking, and pulling ready-made sector reports into thesis work and investment committee prep.', 'Global startup database with 2,000+ sector taxonomies and curated deal feeds', '["Pull a curated daily deal feed for a specific sub-sector and route it to the CRM","Build a market map of emerging players in a niche taxonomy ahead of a thesis sprint"]', 'https://tracxn.com', 'https://www.google.com/s2/favicons?domain=tracxn.com&sz=128', 'PAID', 0, NULL, 'cat-2', NULL, NULL, 1777150116019, 1777150116019), ('t-24', 'twitter', 'Twitter', 'The default real-time public feed, where technical founders ship updates, LPs debate markets, and category conversations unfold in the open. Lists, search, Spaces, and quote posts turn it into a live radar for builder momentum, reputation, and narrative. Used by VCs to spot technical founders building in public, track portfolio signal, and warm up relationships with reply threads long before a first meeting.', 'Real-time public conversation where founders build in public and VCs watch', '["Curate lists of builders in a target sector and watch for repo launches or stealth hints","Engage a founder through thoughtful replies to warm up a cold outreach later in the week"]', 'https://x.com', 'https://www.google.com/s2/favicons?domain=x.com&sz=128', 'FREE', 0, NULL, 'cat-2', NULL, NULL, 1777150116019, 1777150116019), ('t-25', 'venture-intelligence', 'Venture Intelligence', 'A veteran India private-markets database with 25,000+ PE/VC transactions and 15,000+ M&A deals going back to 1999, paired with financials on 800,000+ companies. League tables rank funds, bankers, and law firms by activity; APIs expose funding and financial feeds. Used by India-focused VCs for historical comp analysis, competitive benchmarking, and building league-table visibility ahead of LP meetings.', 'India-focused PE, VC, and M&A intelligence with deal data going back to 1999', '["Pull a decade of Indian PE/VC comparable deals to anchor valuation in an IC memo","Track league-table rankings and deal volumes to benchmark the fund against India peers"]', 'https://ventureintelligence.info', 'https://www.ventureintelligence.info/static/images/icon.png', 'PAID', 0, NULL, 'cat-2', NULL, NULL, 1777150116019, 1777150116019), ('t-26', '1lattice', '1Lattice', 'An Indian market intelligence platform combining survey panels, expert networks, and sector research into a single workflow. Teams run brand tracking, concept testing, competitive scans, and retail audits, then layer on expert calls when qualitative depth is needed. Investors lean on 1Lattice for primary market sizing, sector deep-dives, and diligence checks on consumer and fintech theses.', 'AI market intelligence platform with B2C/B2B panels and expert networks', '["Run primary consumer surveys to validate market size and pricing assumptions on a prospective consumer investment","Commission expert calls and retail audits during diligence to pressure-test founder claims with ground-truth data"]', 'https://1lattice.com', 'https://www.google.com/s2/favicons?domain=1lattice.com&sz=128', 'ENTERPRISE', 0, NULL, 'cat-3', NULL, NULL, 1777150116019, 1777150116019), ('t-27', 'ahrefs', 'Ahrefs', 'The reference SEO platform, built on one of the largest web crawlers outside the search engines themselves. Site Explorer, Keywords Explorer, and Content Explorer expose organic traffic, backlink profiles, and keyword rankings for any domain. Investors use it to validate founder-reported growth, map organic competitors in a category, and spot sectors where search demand is quietly compounding.', 'SEO and competitive intelligence toolkit for domain traffic and keyword analysis', '["Verify a startup''s organic traffic trajectory against claimed growth before writing a check","Map search demand and competitive density across a thesis to find under-covered categories"]', 'https://ahrefs.com', 'https://assets-3b70.kxcdn.com/images/mediakit/logo_blue@2x.png?v=2', 'PAID', 0, NULL, 'cat-3', NULL, NULL, 1777150116019, 1777150116019) ON CONFLICT(id) DO UPDATE SET slug = excluded.slug, name = excluded.name, description = excluded.description, short_desc = excluded.short_desc, use_cases = excluded.use_cases, website_url = excluded.website_url, logo_url = excluded.logo_url, pricing_model = excluded.pricing_model, is_featured = excluded.is_featured, featured_order = excluded.featured_order, category_id = excluded.category_id, extra_category_slugs = excluded.extra_category_slugs, archived_at = excluded.archived_at, updated_at = excluded.updated_at;
INSERT INTO tools (id, slug, name, description, short_desc, use_cases, website_url, logo_url, pricing_model, is_featured, featured_order, category_id, extra_category_slugs, archived_at, created_at, updated_at) VALUES ('t-28', 'alphasense', 'AlphaSense', 'A market intelligence engine that indexes SEC filings, broker research, earnings transcripts, news, and the Tegus library of expert interviews. Generative search and deep research agents surface cited answers across millions of documents, with private workspaces for internal notes and memos. Funds use it to scope new sectors, track portfolio comparables, and pull expert perspectives into diligence without chasing PDFs.', 'AI search across filings, broker research, and expert call transcripts', '["Scan expert transcripts and filings to map competitive dynamics in a new sector before a first meeting","Pull cited quotes from earnings calls and analyst research to stress-test a portfolio company''s thesis"]', 'https://alpha-sense.com', 'https://www.google.com/s2/favicons?domain=alpha-sense.com&sz=128', 'ENTERPRISE', 0, NULL, 'cat-3', NULL, NULL, 1777150116019, 1777150116019), ('t-30', 'clearbit', 'Clearbit', 'A B2B data layer, now part of HubSpot, that enriches emails, domains, and IP addresses into standardised company and contact records. Firmographics, role seniority, industry codes, and corporate hierarchies flow directly into CRMs and forms, with reveal tools exposing which companies visit a website. VC teams wire it into their CRM to enrich inbound dealflow and spot warm intros hiding in team profiles.', 'B2B data enrichment for company, contact, and website visitor intelligence', '["Auto-enrich inbound founder emails with firmographic and team data before the first diligence call","Reveal which portfolio targets are visiting the fund website to prioritise outbound follow-up"]', 'https://clearbit.com', 'https://www.google.com/s2/favicons?domain=clearbit.com&sz=128', 'PAID', 0, NULL, 'cat-3', NULL, NULL, 1777150116019, 1777150116019), ('t-31', 'data-ai', 'Data AI', 'Formerly App Annie and now part of Sensor Tower, data.ai tracks download volumes, revenue estimates, active users, retention, and ad spend across mobile apps and games worldwide. Benchmarks span genres, geographies, and publishers, with creative libraries covering the major ad networks. Consumer and gaming investors use it to size categories, benchmark portfolio apps against rivals, and spot breakout titles before they surface in league tables.', 'Mobile market intelligence for app downloads, revenue, and engagement', '["Benchmark a prospective mobile investment''s downloads and revenue against category leaders during diligence","Track portfolio app retention and ad spend share of voice against direct competitors each quarter"]', 'https://data.ai', 'https://www.google.com/s2/favicons?domain=data.ai&sz=128', 'PAID', 0, NULL, 'cat-3', NULL, NULL, 1777150116019, 1777150116019), ('t-32', 'g2', 'G2', 'The default peer review site for B2B software, covering over two hundred thousand products with validated user reviews, category grids, and buyer intent data. Quadrants and momentum scores surface which vendors are gaining traction in a category and where incumbents are slipping. VC teams scan G2 to triangulate product-market fit signals, benchmark SaaS competitors, and read the review voice of customers before writing a term sheet.', 'Peer review marketplace and buyer intent signals for B2B software', '["Compare a target SaaS company against category peers on review velocity, ratings, and satisfaction scores","Read unfiltered customer reviews to surface product gaps and churn risks before a SaaS investment"]', 'https://g2.com', 'https://www.google.com/s2/favicons?domain=g2.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-3', NULL, NULL, 1777150116019, 1777150116019), ('t-33', 'glg', 'GLG', 'The largest expert network in the world, with over a million vetted specialists spanning former executives, physicians, engineers, and government officials. Clients book one-on-one consultations, surveys, and advisory engagements, with compliance controls that keep calls inside public-information boundaries. Funds rely on GLG during diligence to talk directly with former operators, channel partners, and customers of a target company before final investment committee.', 'Expert network connecting investors with specialists for diligence calls', '["Book expert calls with former operators and customers to validate a target company''s competitive position","Commission targeted surveys of industry practitioners to test a sector thesis before leading a round"]', 'https://glginsights.com', 'https://www.google.com/s2/favicons?domain=glginsights.com&sz=128', 'ENTERPRISE', 0, NULL, 'cat-3', NULL, NULL, 1777150116019, 1777150116019), ('t-34', 'gartner', 'Gartner', 'The dominant research and advisory firm for enterprise technology, with Magic Quadrants, Hype Cycles, and category deep dives on every major software market. Paid subscriptions include analyst inquiry calls, forecast data, and benchmarking libraries. VC firms lean on Gartner reports during diligence to size categories, validate competitive positioning, and pressure-test a founder''s view of where a market is actually heading.', 'Technology research, Magic Quadrants, and analyst advisory for enterprise buyers', '["Size TAM and validate category framing before writing a check with Magic Quadrant context","Book analyst inquiry calls to pressure-test a founder''s roadmap against enterprise buying signals"]', 'https://gartner.com', 'https://www.google.com/s2/favicons?domain=gartner.com&sz=128', 'ENTERPRISE', 0, NULL, 'cat-3', NULL, NULL, 1777150116019, 1777150116019), ('t-35', 'kavi-research', 'Kavi Research', 'An expert network built for investors researching Indian businesses, with a library of recorded investor-led interviews plus direct expert booking without the usual markups. Experts are operators and domain specialists across consumer, fintech, and B2B sectors. Used by funds to accelerate diligence on Indian companies, stress-test theses, and gather primary signal without running a full consulting engagement or paying GLG-tier rates.', 'Investor-led expert interviews and on-demand expert calls focused on India', '["Pull recorded interviews on a target sector to shortcut the first pass of diligence research","Book direct calls with operators to validate a founder''s channel claims or unit economics"]', 'https://joinkavi.com', 'https://www.google.com/s2/favicons?domain=joinkavi.com&sz=128', 'PAID', 0, NULL, 'cat-3', NULL, NULL, 1777150116019, 1777150116019), ('t-36', 'owler', 'Owler', 'A company intelligence platform built on crowdsourced and editorial data, covering revenue estimates, funding, headcount, news, and competitive sets for millions of private and public companies. Daily alerts and competitor graphs run inside the browser or Salesforce. Used by VC associates to build watchlists on private companies, track portfolio competitor moves, and catch funding or exec-change news before it filters into Crunchbase.', 'Company intelligence with crowd-sourced data and competitor news alerts', '["Set daily alerts on portfolio companies and their competitors to catch funding and exec moves early","Build quick competitor maps during diligence using Owler''s crowdsourced revenue and headcount estimates"]', 'https://owler.com', 'https://www.google.com/s2/favicons?domain=owler.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-3', NULL, NULL, 1777150116019, 1777150116019), ('t-37', 'redseer', 'RedSeer', 'A strategy consulting and research firm with deep coverage of Indian and MEA consumer, fintech, and B2B markets. Redsights publications and custom reports map category structure, competitive share, and unit economics across sectors from quick commerce to neobanking. Widely used by VC firms investing in India to size markets during diligence, benchmark portfolio companies against category leaders, and commission bespoke theses on emerging verticals.', 'India-focused strategy research on consumer, fintech, and B2B markets', '["Commission custom market maps and sizing studies to anchor investment theses in Indian consumer or fintech","Benchmark a portfolio company''s GMV and take rate against Redseer category data before a follow-on"]', 'https://redseer.com', 'https://www.google.com/s2/favicons?domain=redseer.com&sz=128', 'ENTERPRISE', 0, NULL, 'cat-3', NULL, NULL, 1777150116019, 1777150116019), ('t-38', 'semrush', 'SEMRush', 'A digital marketing platform covering keyword research, backlink analysis, site audits, and traffic and market intelligence across competitor domains. The newer AI Visibility module tracks how brands appear inside LLM answers. VC firms use Semrush during diligence to read a startup''s organic traffic trajectory, compare digital share of voice against category incumbents, and check whether paid growth is covering for weak SEO fundamentals.', 'SEO, traffic analytics, and competitive digital marketing intelligence', '["Pull organic traffic and keyword trend charts during diligence to sanity-check a startup''s growth claims","Compare a target''s backlink profile and domain authority against direct competitors in the category"]', 'https://semrush.com', 'https://www.google.com/s2/favicons?domain=semrush.com&sz=128', 'PAID', 0, NULL, 'cat-3', NULL, NULL, 1777150116019, 1777150116019), ('t-39', 'similarweb', 'Similarweb', 'A digital intelligence platform estimating website and mobile app traffic, engagement, acquisition mix, and audience overlap across millions of properties. Retail modules add marketplace and Amazon analytics. VC firms rely on Similarweb to triangulate user growth on private companies without portal access, map category share between a target and its rivals, and watch traffic trends in portfolio companies quarter over quarter.', 'Web and app traffic intelligence with competitive benchmarking data', '["Triangulate traffic and engagement on private targets when data-room access is limited during early diligence","Track monthly visit share across a category to spot which portfolio bet is pulling ahead of competitors"]', 'https://similarweb.com', 'https://www.google.com/s2/favicons?domain=similarweb.com&sz=128', 'PAID', 0, NULL, 'cat-3', NULL, NULL, 1777150116019, 1777150116019), ('t-40', 'statista', 'Statista', 'A subscription statistics portal aggregating market data, forecasts, and consumer survey results across 170 industries and 150+ countries. Analyst-ready charts and export-friendly datasets cover everything from EV adoption to SaaS spend. Used by investors to anchor market-size slides in memos with citable third-party sources, pull category forecasts for thesis work, and sanity-check TAM numbers a founder has put in a deck.', 'Global statistics portal with market sizing, forecasts, and consumer data', '["Pull citable market-size and forecast charts for memo appendices without commissioning custom research","Sanity-check TAM and CAGR numbers in a pitch deck against Statista''s published consumer and industry data"]', 'https://statista.com', 'https://www.google.com/s2/favicons?domain=statista.com&sz=128', 'PAID', 0, NULL, 'cat-3', NULL, NULL, 1777150116019, 1777150116019), ('t-41', 'arc-news', 'Arc', 'A Bengaluru-based publication from ex-Economic Times and Reuters journalists, decoding the strategies, leadership, and shareholding behind India''s fastest-growing private companies. Formats split between longer In-Depth reads and short Bulletins that cover earnings, org shifts, and cap-table moves. VCs use it to track the private-company narratives that shape portfolio benchmarks and competitive diligence.', 'Data-led reportage on India''s high-growth private companies', '["Read Bulletins to catch cap-table and leadership changes at private Indian companies weekly","Use In-Depth pieces to pressure-test competitive theses before an investment committee or partner meeting"]', 'https://thearcweb.com', 'https://www.google.com/s2/favicons?domain=thearcweb.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-4', NULL, NULL, 1777150116019, 1777150116019), ('t-42', 'economic-times', 'Economic Times', 'India''s flagship business daily, with live Sensex and Nifty coverage, IPO and earnings tracking, policy reporting, and a dedicated startup desk. The newsroom pairs wire-speed breaking news with opinion columns and sector explainers across banking, energy, telecom, and consumer. VC readers lean on it for macro context, public-market comparables, and early signals on regulation affecting portfolio companies.', 'India''s largest business daily covering markets, companies, policy', '["Skim morning headlines for regulatory and macro developments that affect Indian portfolio companies","Pull public-market comparables and IPO updates when sizing late-stage opportunities for the team"]', 'https://economictimes.indiatimes.com', 'https://www.google.com/s2/favicons?domain=economictimes.indiatimes.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-4', NULL, NULL, 1777150116019, 1777150116019), ('t-43', 'entrepreneur-india', 'Entrepreneur India', 'The India edition of Entrepreneur mixes short business-news updates on funding rounds and leadership moves with founder interviews and operator-oriented how-to pieces on marketing, hiring, and fundraising. Coverage skims across D2C, fintech, and emerging tech, with a practical tone pitched at founders rather than institutional investors. Useful for a quick take on what operators are reading in-market.', 'Practical founder stories and India business news with a how-to voice', '["Scan founder features to understand how category leaders are framing their own story","Share operator how-to pieces with portfolio founders working on sales or hiring"]', 'https://entrepreneur.com', 'https://www.google.com/s2/favicons?domain=entrepreneur.com&sz=128', 'FREE', 0, NULL, 'cat-4', NULL, NULL, 1777150116019, 1777150116019), ('t-44', 'forbes', 'Forbes', 'A global business and finance brand known for its wealth rankings, the 30 Under 30 cohort, Cloud 100, and Next Billion-Dollar Startups lists. Daily coverage spans venture capital, enterprise AI, money and markets, leadership, and personal finance, with contributor columns layered over staff reporting. Investors use the lists for surfacing emerging names and the newsroom for global macro and tech context.', 'Global business coverage, billionaire rankings, and startup lists', '["Mine Cloud 100 and Next Billion-Dollar Startups for names worth a warm intro","Reference 30 Under 30 cohorts when mapping rising founders across a target category"]', 'https://forbes.com', 'https://www.google.com/s2/favicons?domain=forbes.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-4', NULL, NULL, 1777150116019, 1777150116019), ('t-45', 'inc42', 'Inc42', 'India''s most-read startup publication, tracking funding rounds, founder moves, and sector shifts across fintech, edtech, healthtech, ecommerce, and EVs. Franchises like What The Financials and 30 Startups To Watch sit alongside running coverage of policy and the unicorn and soonicorn pipeline. Investors use it for a weekday pulse on Indian dealflow and quick context on any named company.', 'India startup media with funding rounds, sector deep dives, policy', '["Read the weekly funding roundup to stay current on Indian early-stage rounds","Pull What The Financials pieces when sizing unit economics on a target company"]', 'https://inc42.com', 'https://www.google.com/s2/favicons?domain=inc42.com&sz=128', 'FREE', 1, NULL, 'cat-4', NULL, NULL, 1777150116019, 1777150116019), ('t-46', 'the-ken', 'Ken', 'A subscription newsroom publishing one carefully reported story a day across Indian business, startups, technology, and healthcare. Franchise newsletters like The Nutgraf, Daybreak, Trade Tricks, and Two by Two unpack narratives behind the headlines with a calm, analytical voice and few-but-rich editorial cadence. Investors read it for the context and second-order takes the wire services miss.', 'Subscription longform on Indian business, startups, and healthcare', '["Read the daily long story to understand the why behind a competitor''s strategic move","Forward Two by Two frameworks to LPs when explaining Indian category dynamics simply"]', 'https://the-ken.com', 'https://www.google.com/s2/favicons?domain=the-ken.com&sz=128', 'PAID', 0, NULL, 'cat-4', NULL, NULL, 1777150116019, 1777150116019), ('t-47', 'livemint', 'Live Mint', 'Hindustan Times Group''s business paper, partnered with The Wall Street Journal and The Economist for global coverage. Strong on live markets, company results, mutual funds, personal finance, and the startup desk, with Mint Explainers and Long Story features adding depth. VCs use it for public-market signal, LP-grade macro pieces, and companion context alongside the startup trade press.', 'India business daily with markets, companies, startups, personal finance', '["Check Mint Explainers when a macro or regulatory story needs a quick grounded read","Track company results each quarter to update comparables for late-stage portfolio reviews"]', 'https://livemint.com', 'https://www.google.com/s2/favicons?domain=livemint.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-4', NULL, NULL, 1777150116019, 1777150116019), ('t-48', 'money-control', 'Money Control', 'India''s most-used financial markets portal, built around live quotes, stock screeners, mutual fund data, and a deep IPO section, with layered coverage of companies, startups, and personal finance. Tools like the fundamental and technical scanners sit next to news, and the MC Pro tier adds research. Investors use it for public-market data, IPO pipelines, and real-time price action on listed comparables.', 'India markets portal covering stocks, IPOs, mutual funds, and startups', '["Pull quick fundamentals and price history when building a public comparable set","Track the IPO pipeline to anticipate exit windows for late-stage portfolio companies"]', 'https://moneycontrol.com', 'https://www.google.com/s2/favicons?domain=moneycontrol.com&sz=128', 'FREE', 0, NULL, 'cat-4', NULL, NULL, 1777150116019, 1777150116019), ('t-49', 'morning-context', 'The Morning Context', 'Founded by former Ken and Mint journalists, this subscription-only newsroom publishes one longread, one opinion column, and one news explainer each weekday across three themes: Internet, Business, and Chaos. Reporting is deliberately narrow and deep, often revealing the power dynamics and regulatory undercurrents behind startup headlines. Investors subscribe for original scoops that rarely appear in the wire press.', 'Subscription daily on Indian internet, business, and policy chaos', '["Read the daily longread to understand internal dynamics at Indian consumer and fintech players","Forward explainers to LPs when a policy shift changes the shape of a sector"]', 'https://themorningcontext.com', 'https://www.google.com/s2/favicons?domain=themorningcontext.com&sz=128', 'PAID', 0, NULL, 'cat-4', NULL, NULL, 1777150116019, 1777150116019), ('t-50', 'techcrunch', 'TechCrunch', 'The default global wire for startup news, funding announcements, and big tech moves, with heavy AI and venture coverage, plus podcasts like Equity and StrictlyVC. Reporting runs the full stack from seed rounds and acquisitions to product launches at Apple, OpenAI, and Meta. VCs use it for daily deal signal, competitor monitoring, and the fastest read on what US founders are raising on.', 'Global tech and startup news with heavy VC funding coverage', '["Scan the morning feed for US funding rounds that shape global category benchmarks","Use Equity and StrictlyVC podcasts to stay current on Silicon Valley deal sentiment"]', 'https://techcrunch.com', 'https://www.google.com/s2/favicons?domain=techcrunch.com&sz=128', 'FREE', 0, NULL, 'cat-4', NULL, NULL, 1777150116019, 1777150116019), ('t-51', 'the-generalist', 'The Generalist', 'Mario Gabriele''s subscriber newsletter with over 160,000 readers, built around long-form deep dives on private companies, venture firms, and frontier themes across tech and Web3. Writing is essay-length and thesis-driven rather than newsy, with investor-friendly framing and clean charts. VCs read it for category maps and founder-and-firm profiles that hold up as reference material long after publication.', 'Mario Gabriele''s deep dives on tech companies, VC, and frontier themes', '["Read company deep dives before taking a first meeting with a category-adjacent founder","Share VC firm profiles with LPs to anchor discussion of peer fund strategies"]', 'https://generalist.com', 'https://www.google.com/s2/favicons?domain=generalist.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-4', NULL, NULL, 1777150116019, 1777150116019), ('t-52', 'vccircle', 'VCCircle', 'The trade publication of record for Indian private equity, venture capital, and M&A, with sections dedicated to fund closes, LP activity, exits, and sector deal flow across healthcare, infrastructure, TMT, and consumer. The LP Corner franchise tracks fund raises and GP interviews rarely covered elsewhere. Funds use the Premium tier for competitive intel on peer firms and sector deal tempo.', 'India PE, VC, and M&A trade press with LP and fund coverage', '["Track LP Corner for peer fund raises and incoming capital in your strategy","Monitor M&A and exit coverage to benchmark return multiples across Indian sectors"]', 'https://vccircle.com', 'https://www.google.com/s2/favicons?domain=vccircle.com&sz=128', 'PAID', 0, NULL, 'cat-4', NULL, NULL, 1777150116019, 1777150116019), ('t-53', 'yourstory', 'YourStory', 'One of India''s oldest startup media platforms, known for accessible founder profiles, weekly funding roundups, and the Unicorns of India franchise. Coverage spans AI, fintech, agritech, D2C, and women-led businesses, with a narrative-first tone that reaches beyond the insider audience. Investors use it to spot early-stage founders and to read how portfolio companies are framing their own stories to a broader audience.', 'India startup media built around founder stories and weekly roundups', '["Read founder profiles to surface emerging names before institutional coverage catches up","Share weekly funding roundups with junior team members to build sector context"]', 'https://yourstory.com', 'https://www.google.com/s2/favicons?domain=yourstory.com&sz=128', 'FREE', 0, NULL, 'cat-4', NULL, NULL, 1777150116019, 1777150116019) ON CONFLICT(id) DO UPDATE SET slug = excluded.slug, name = excluded.name, description = excluded.description, short_desc = excluded.short_desc, use_cases = excluded.use_cases, website_url = excluded.website_url, logo_url = excluded.logo_url, pricing_model = excluded.pricing_model, is_featured = excluded.is_featured, featured_order = excluded.featured_order, category_id = excluded.category_id, extra_category_slugs = excluded.extra_category_slugs, archived_at = excluded.archived_at, updated_at = excluded.updated_at;
INSERT INTO tools (id, slug, name, description, short_desc, use_cases, website_url, logo_url, pricing_model, is_featured, featured_order, category_id, extra_category_slugs, archived_at, created_at, updated_at) VALUES ('t-54', 'entrackr', 'Entrackr', 'A scoop-driven Indian startup newsroom, known for breaking funding rounds, ESOP buyback moves, and leadership changes ahead of the broader press. The Fintrackr franchise pulls revenue, loss, and GMV data from regulatory filings into readable company snapshots. Investors use it for the earliest word on rounds in motion and for quick pre-meeting financial context on any privately held Indian target.', 'India startup scoops, funding rounds, and company financials', '["Check Fintrackr for filed financials before a first meeting with a private Indian company","Monitor exclusive scoops for rounds in motion to time outbound on competitive deals"]', 'https://entrackr.com', 'https://www.google.com/s2/favicons?domain=entrackr.com&sz=128', 'FREE', 0, NULL, 'cat-4', NULL, NULL, 1777150116019, 1777150116019), ('t-55', 'chatgpt', 'ChatGPT', 'The most widely adopted AI product in the world, and in finance too. Custom GPTs, document analysis, browsing, canvas, voice, and Deep Research turn it into a portable reasoning layer rather than a single tool. Widely used by VC firms to draft first-cut memos from decks, summarise earnings transcripts, and run diligence Q&A against Custom GPTs loaded with firm playbooks.', 'The most widely adopted AI product, now a general reasoning layer', '["Draft first-cut investment memos and summarise founder decks into structured diligence notes","Build Custom GPTs on firm playbooks, portfolio data, and saved market research"]', 'https://openai.com', 'https://www.google.com/s2/favicons?domain=openai.com&sz=128', 'FREEMIUM', 1, NULL, 'cat-5', NULL, NULL, 1777150116019, 1777150116019), ('t-56', 'claude', 'Claude', 'Anthropic''s AI assistant, favoured for careful long-context reading, writing, and code analysis. Projects keep firm documents and context together across conversations, Artifacts render interactive drafts and diagrams inline, and Claude Code extends the model into the terminal. Widely used by VC firms to read through data rooms, pressure-test memos, and turn founder transcripts into structured diligence notes.', 'Anthropic''s assistant favoured for long-context reasoning and writing', '["Summarise long data room documents and financial filings with citations back to the source","Run memo edits, thesis critiques, and competitive teardowns inside per-deal Projects with shared context"]', 'https://claude.ai', 'https://www.google.com/s2/favicons?domain=claude.ai&sz=128', 'FREEMIUM', 1, NULL, 'cat-5', NULL, NULL, 1777150116019, 1777150116019), ('t-57', 'gemini', 'Gemini', 'Google''s consumer AI assistant, now plugged into Gmail, Docs, Sheets, Drive, and Search. Deep Research runs autonomous multi-step investigations, while interactive charts, 3D models, and the 1M-token context window suit long documents and messy decks. Widely used by VC firms who already live in Workspace for quick triage of inbound, meeting recaps, and first-pass market scans.', 'Google''s AI assistant plugged into Workspace, Search, and the browser', '["Summarise inbound pitches inside Gmail and draft replies without leaving the thread","Run Deep Research sweeps across markets, competitors, and founder backgrounds before a first call"]', 'https://gemini.google.com', 'https://www.google.com/s2/favicons?domain=gemini.google.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-5', NULL, NULL, 1777150116019, 1777150116019), ('t-58', 'manus', 'Manus', 'An autonomous AI agent that takes a brief and returns finished work, not just a reply. Manus plans a task, opens a browser, writes code, builds slide decks or websites, and hands back a file. Wide Research runs parallel sub-agents across the open web. Used by VC teams to assemble market maps, build competitor teardowns, and draft sector decks without wiring up a research stack.', 'Autonomous AI agent that plans, browses, and delivers finished work', '["Build market maps and competitor teardowns by pointing the agent at a sector brief","Turn raw research notes into a polished slide deck or memo the team can edit"]', 'https://manus.ai', 'https://www.google.com/s2/favicons?domain=manus.ai&sz=128', 'PAID', 0, NULL, 'cat-5', NULL, NULL, 1777150116019, 1777150116019), ('t-60', 'perplexity', 'Perplexity', 'An AI answer engine that cites its sources on every response, built for fast factual research rather than open-ended chat. Pro opens up stronger models, document search, and Spaces for saved context, while Comet adds an AI browser and Pages produces shareable research reports. Used by VC firms for rapid market scans, founder background checks, and grounded answers during a live call.', 'AI answer engine that cites its sources on every response', '["Run sector scans and competitor look-ups with sourced citations you can paste into a memo","Build Spaces per thesis and let the team ask questions against saved research and filings"]', 'https://perplexity.ai', 'https://www.google.com/s2/favicons?domain=perplexity.ai&sz=128', 'FREEMIUM', 1, NULL, 'cat-5', NULL, NULL, 1777150116019, 1777150116019), ('t-62', 'deepseek', 'DeepSeek', 'A Chinese AI lab shipping strong open-source reasoning and coding models alongside a free chat app and a low-cost API. The V3 and R1 lines are widely benchmarked against frontier closed models, and the weights are downloadable for private deployment. Used by VC analysts and technical investors as a second AI opinion and for diligence work that benefits from a cheaper, self-hostable model.', 'Open-source reasoning models with a free chat app and cheap API', '["Run a second-opinion reasoning pass on memos, models, and technical diligence questions","Self-host an open-weight model for sensitive documents that cannot leave the firm"]', 'https://deepseek.com', 'https://www.google.com/s2/favicons?domain=deepseek.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-5', NULL, NULL, 1777150116019, 1777150116019), ('t-63', 'standard-metrics', 'Standard Metrics', 'A portfolio management platform built for VC and PE firms, covering automated data collection from founders, structured metrics storage, an AI analyst for natural-language queries, and benchmarking against 10,000+ venture-backed companies. Used by funds including Bessemer, General Catalyst, and Accel to cut reporting time, standardise KPIs across the book, and produce LP updates and dashboards without rebuilding spreadsheets every quarter.', 'Portfolio monitoring and LP reporting with benchmarks against 10,000+ startups', '["Automate quarterly KPI collection from founders and normalise metrics across the fund''s entire portfolio","Generate LP reports and benchmark a portfolio company''s growth against anonymised peer data by stage"]', 'https://standardmetrics.io', 'https://www.google.com/s2/favicons?domain=standardmetrics.io&sz=128', 'PAID', 0, NULL, 'cat-6', NULL, NULL, 1777150116019, 1777150116019), ('t-64', 'vestberry', 'Vestberry', 'An AI-powered portfolio platform that consolidates fund, company, and market data into a single workspace for venture investors. Modules handle automated data collection from founders, institutional-grade LP reports, and analytics that flag underperforming bets against market comps. Used by 500+ funds to retire spreadsheet-based tracking, standardise reporting cadence across the portfolio, and give partners a live view of fund performance between board meetings.', 'VC portfolio monitoring with automated data collection and LP reporting', '["Replace spreadsheet trackers with automated KPI pulls and a shared dashboard across the full portfolio","Build audit-ready LP reports and flag underperforming companies using Vestberry''s benchmark analytics"]', 'https://vestberry.com', 'https://www.google.com/s2/favicons?domain=vestberry.com&sz=128', 'PAID', 0, NULL, 'cat-6', NULL, NULL, 1777150116019, 1777150116019), ('t-71', 'angellist', 'AngelList', 'AngelList India runs the legal, banking, and software rails behind Indian syndicates, SPVs, and rolling funds. Roll-Up Vehicles, pre-funded SPVs, and warehouse structures cover different deal patterns, and the platform handles onboarding, capital calls, distributions, and tax paperwork. Used by Indian angels, scouts, and emerging managers to run deal-by-deal vehicles without assembling lawyers, fund admins, and bankers for every investment.', 'India''s default platform for running syndicates, SPVs, and rolling funds', '["Spin up an SPV or RUV per deal and onboard LPs with KYC, capital calls, and distributions handled","Run a rolling fund or syndicate with investor dashboards, reporting, and tax forms built in"]', 'https://angellistindia.com', 'https://www.google.com/s2/favicons?domain=angellistindia.com&sz=128', 'PAID', 1, NULL, 'cat-9', NULL, NULL, 1777150116019, 1777150116019), ('t-72', 'incentive-finance', 'Incentive Finance', 'Incentiv positions itself as infrastructure for private markets, building the admin and investor-facing rails that sit under Indian syndicates, SPVs, and private deals. The platform covers vehicle setup, investor onboarding, and ongoing operations so deal leads can run transactions end to end. Used by Indian angels, syndicate leads, and emerging managers who want a modern stack rather than stitching together lawyers, fund admins, and spreadsheets.', 'Infrastructure layer for Indian private market deals and syndicates', '["Structure and launch an SPV or syndicate vehicle for a specific Indian private market deal","Onboard investors, manage capital calls, and keep LP reporting in one dashboard"]', 'https://incentiv.finance', 'https://www.google.com/s2/favicons?domain=incentiv.finance&sz=128', 'PAID', 0, NULL, 'cat-9', NULL, NULL, 1777150116019, 1777150116019), ('t-73', 'infinyte-club', 'Infynite Club', 'Infinyte Club is a wealth platform aimed at Indian founders, operators, and angels, registered as a Category-I Angel Fund. Members track net worth across accounts, access curated public-market portfolios, and invest alongside established angels and VCs in seed to pre-IPO rounds. Used by eligible Indian angel investors who want structured access to private deals and a single view of their portfolio across asset classes.', 'Wealth and private-market platform for Indian founders and operators', '["Co-invest alongside established angels and VCs in curated Indian seed and growth rounds","Track net worth, public portfolios, and private holdings across accounts in one dashboard"]', 'https://infinyte.club', 'https://www.google.com/s2/favicons?domain=infinyte.club&sz=128', 'PAID', 0, NULL, 'cat-9', NULL, NULL, 1777150116019, 1777150116019), ('t-74', 'letsventure', 'LetsVenture', 'LetsVenture, now operating under LVX Ventures, is one of India''s longest-running platforms for angel investing and syndication. It covers deal discovery, syndicate formation, trust-based AIF structures, and fund administration for angels, family offices, and emerging managers. Used by Indian investors to source rounds, run syndicates with pooled LPs, and manage the paperwork and reporting that sit behind each vehicle.', 'Long-running Indian angel and syndication platform for startups and funds', '["Discover Indian startup rounds and form syndicates of angels to back a single deal","Run an AIF or trust-based fund with onboarding, capital calls, and LP reporting handled"]', 'https://letsventure.com', 'https://www.google.com/s2/favicons?domain=letsventure.com&sz=128', 'PAID', 0, NULL, 'cat-9', NULL, NULL, 1777150116019, 1777150116019), ('t-75', 'make', 'Make', 'Make is a visual automation platform where workflows are drawn as node-and-line scenarios rather than linear rules. It connects more than 3,000 apps, supports branching, iteration, and error handling, and now ships AI agents that orchestrate steps dynamically. Used by VC ops and platform teams to pipe deal data between CRM, forms, email, and Slack without writing code.', 'Visual automation builder connecting 3,000+ apps with AI agents', '["Route inbound decks from forms and email into CRM with enrichment and Slack alerts","Build agent-driven scenarios that summarise founder updates and post them to the right channel"]', 'https://make.com', 'https://www.google.com/s2/favicons?domain=make.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-10', NULL, NULL, 1777150116019, 1777150116019), ('t-76', 'phantombuster', 'Phantom Buster', 'PhantomBuster runs cloud-based automations called Phantoms that scrape, enrich, and act on data from LinkedIn, Sales Navigator, and other sites. It chains prospecting, enrichment, and outreach into repeatable flows, with CRM sync and a Chrome extension for manual steps. Used by VC sourcing and platform teams to build founder and operator lists, map portfolios, and run warm-intro campaigns at scale.', 'LinkedIn-first automation for scraping, enrichment, and outreach', '["Scrape LinkedIn events, company pages, and Sales Nav searches into enriched founder lists","Automate LinkedIn connection requests and message follow-ups for sourcing and portfolio talent pipelines"]', 'https://phantombuster.com', 'https://www.google.com/s2/favicons?domain=phantombuster.com&sz=128', 'PAID', 0, NULL, 'cat-10', NULL, NULL, 1777150116019, 1777150116019), ('t-77', 'zapier', 'Zapier', 'Zapier is the default no-code automation layer connecting more than 9,000 apps through triggers and actions called Zaps. Tables holds light databases, Interfaces builds simple front-ends, Canvas diagrams flows, and Agents run AI steps across the same integrations. Used by VC platform and operations teams to wire deal intake forms, CRM, email, and Slack into a single pipeline without an engineer in the loop.', 'The default no-code automation layer across 9,000+ apps', '["Push new CRM deals into Slack, Notion, and data rooms without writing integration code","Automate newsletter intake, event RSVPs, and inbound triage straight from forms and email"]', 'https://zapier.com', 'https://www.google.com/s2/favicons?domain=zapier.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-10', NULL, NULL, 1777150116019, 1777150116019), ('t-79', 'discord', 'Discord', 'Discord is a real-time chat platform built around persistent servers split into voice, video, and text channels. Members drop into rooms, jump between live huddles, and keep searchable threads alongside bots and custom integrations. Originally built for gaming communities, it is now widely used by VC firms and founders to run scout networks, investor-only communities, and public founder hangouts that would feel too heavy for Slack.', 'Server-based chat platform with voice, video, and topic channels', '["Host a scout community where drive-by voice rooms and topic channels keep deal chatter flowing","Run a portfolio or LP community with gated channels, live AMAs, and searchable message history"]', 'https://discord.com', 'https://www.google.com/s2/favicons?domain=discord.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-11', NULL, NULL, 1777150116019, 1777150116019), ('t-80', 'slack', 'Slack', 'Slack is the default platform for internal team communication, with channels, threads, and shared rooms that replace endless reply-all email. Huddles add lightweight audio and video, canvas captures decisions in context, and the app directory pipes alerts from CRMs, databases, and project tools into the place teams already look. Widely used by VC firms for partner discussion, shared channels with portfolio companies, and the searchable team memory the inbox never provides.', 'Channel-based team chat with huddles, canvas, and deep app integrations', '["Run shared Slack Connect channels with portfolio companies for fast investor support and introductions","Pipe CRM, data room, and Affinity alerts into partner channels so dealflow stays visible"]', 'https://slack.com', 'https://www.google.com/s2/favicons?domain=slack.com&sz=128', 'FREEMIUM', 1, NULL, 'cat-11', NULL, NULL, 1777150116019, 1777150116019), ('t-81', 'telegram', 'Telegram', 'Telegram is a cloud-first messenger built around speed, unlimited media, and groups that scale to 200,000 members. Broadcast channels push one-to-many updates, bots automate workflows through an open API, and chats sync instantly across mobile, desktop, and web. Widely used by VC firms in emerging markets to coordinate with founders, run private deal rooms, and follow crypto and growth-stage communities that live there by default.', 'Fast cloud messenger with large groups, broadcast channels, and open bot APIs', '["Maintain direct lines to portfolio founders in markets where Telegram is the default app","Monitor crypto and emerging-market deal channels where announcements break before Twitter picks them up"]', 'https://telegram.org', 'https://www.google.com/s2/favicons?domain=telegram.org&sz=128', 'FREE', 0, NULL, 'cat-11', NULL, NULL, 1777150116019, 1777150116019), ('t-82', 'whatsapp', 'WhatsApp', 'WhatsApp is the most widely used messaging app in the world, built around encrypted one-to-one chats, group threads, and voice and video calls. Status updates, broadcast lists, and the Business app add light CRM on top of conversation. Widely used by VC firms outside the US to stay in founder chats, route warm intros, and handle fast diligence back-and-forth where email would feel slow and Slack would feel too formal.', 'Encrypted messenger for one-to-one chats, groups, and business threads', '["Keep direct founder threads active for quick check-ins and intro requests between formal updates","Coordinate warm intros and diligence questions across India, SEA, LatAm, and Africa dealflow"]', 'https://whatsapp.com', 'https://www.google.com/s2/favicons?domain=whatsapp.com&sz=128', 'FREE', 1, NULL, 'cat-11', NULL, NULL, 1777150116019, 1777150116019), ('t-83', 'notion-mail', 'Notion Mail', 'Notion Mail is an AI email client on top of Gmail that auto-labels messages and splits the inbox into custom views by sender, domain, label, or calendar. Snippets speed up repeat replies, the Notion-style editor makes composing feel like a doc, and scheduling is built in. Used by VC firms that already live in Notion and want a lighter-touch triage layer over raw Gmail without adopting a separate power-user client.', 'AI email client that sorts Gmail into custom views with Notion-native editing', '["Triage founder intros, LP threads, and portfolio updates into separate views without filter-rule bookkeeping","Compose investment updates and follow-ups with snippets and formatting that match existing Notion docs"]', 'https://mail.notion.com', 'https://www.google.com/s2/favicons?domain=mail.notion.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-12', NULL, NULL, 1777150116019, 1777150116019), ('t-84', 'shortwave', 'Shortwave', 'Shortwave is an AI-native email app layered over Gmail. The assistant writes, schedules, and searches from a single prompt, bundles collapse newsletters and promotions, and split inbox separates important threads from everything else. Natural-language filters automate labels and archives in plain English. Used by VC firms that want Superhuman-style speed with a stronger AI backbone for memo drafting, research threads, and calendar work.', 'AI-native Gmail client with bundles, split inbox, and natural-language agents', '["Summarise long founder update threads and draft replies in the partner''s voice with the AI agent","Auto-bundle LP newsletters, data-room alerts, and portfolio reports into dedicated split-inbox tabs"]', 'https://shortwave.com', 'https://www.google.com/s2/favicons?domain=shortwave.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-12', NULL, NULL, 1777150116019, 1777150116019), ('t-85', 'simplehuman-mail', 'Simplehuman', 'CMDK (formerly Simplehuman) is a Chrome extension that sits on top of Gmail and adds the keyboard-first muscle of pricier clients. A command palette runs everything, single-key actions archive and delete, natural-language snoozing sets reminders, and read receipts track when messages are reopened. Used by VC firms that want Superhuman-style triage speed inside native Gmail without moving their inbox or paying the premium tier.', 'Keyboard-first Gmail extension with a command bar, snooze, and read receipts', '["Clear a 200-message inbox with single-key triage and command-bar actions instead of clicking menus","Snooze founder follow-ups and LP threads in plain English and catch reopened replies with read receipts"]', 'https://simplehuman.email', 'https://www.google.com/s2/favicons?domain=simplehuman.email&sz=128', 'PAID', 0, NULL, 'cat-12', NULL, NULL, 1777150116019, 1777150116019), ('t-86', 'superhuman', 'Superhuman', 'Superhuman is a keyboard-first email client built for people who live in the inbox. AI triage sorts threads into split inboxes, snippets and AI write produce replies in the sender''s voice, and follow-up reminders, send-later, and read status remove the usual inbox friction. Widely used by VC firms to blow through dozens of founder threads, LP updates, and diligence back-and-forth each day without falling behind the deal clock.', 'Keyboard-first email client with AI triage, split inbox, and send-later', '["Triage a founder-heavy inbox twice as fast with split inbox and single-key shortcuts","Draft warm intros and diligence replies with AI write in the partner''s voice before morning standup"]', 'https://superhuman.com', 'https://www.google.com/s2/favicons?domain=superhuman.com&sz=128', 'PAID', 1, NULL, 'cat-12', NULL, NULL, 1777150116019, 1777150116019), ('t-87', 'cal-com', 'Cal.com', 'Cal.com is an open-source scheduling platform that handles bookings, routing, and workflow automation for individuals and teams. It plugs into Google, Outlook, and Apple calendars, runs round-robin and collective events, and exposes an API plus Docker image for firms that want to self-host. Used by VC firms as a Calendly alternative where brand control, privacy, and custom forms for founder intake matter more than the default option.', 'Open-source scheduling platform with routing, workflows, and a self-host option', '["Route inbound founder pitches to the right partner by stage, sector, or geography with a single public link","Self-host scheduling for LP and portfolio meetings where data residency and branding need to stay in-house"]', 'https://cal.com', 'https://www.google.com/s2/favicons?domain=cal.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-13', NULL, NULL, 1777150116019, 1777150116019) ON CONFLICT(id) DO UPDATE SET slug = excluded.slug, name = excluded.name, description = excluded.description, short_desc = excluded.short_desc, use_cases = excluded.use_cases, website_url = excluded.website_url, logo_url = excluded.logo_url, pricing_model = excluded.pricing_model, is_featured = excluded.is_featured, featured_order = excluded.featured_order, category_id = excluded.category_id, extra_category_slugs = excluded.extra_category_slugs, archived_at = excluded.archived_at, updated_at = excluded.updated_at;
INSERT INTO tools (id, slug, name, description, short_desc, use_cases, website_url, logo_url, pricing_model, is_featured, featured_order, category_id, extra_category_slugs, archived_at, created_at, updated_at) VALUES ('t-88', 'calendly', 'Calendly', 'Calendly is the default scheduling platform for sharing availability without the back-and-forth. It supports one-on-one, collective, round-robin, and group events, routes inbound forms to the right owner, and syncs with Google, Outlook, Zoom, Salesforce, and HubSpot. Meeting reminders, workflows, and a built-in notetaker cover the edges. Widely used by VC firms to book founder intros, run diligence calls, and coordinate LP meetings without owning the scheduling logic.', 'Scheduling platform with routing, team events, and 100+ tool integrations', '["Share a partner booking link for founder intros that respects availability across Gmail and Outlook","Route inbound pitch forms to the right investor by sector or stage with round-robin fallbacks"]', 'https://calendly.com', 'https://www.google.com/s2/favicons?domain=calendly.com&sz=128', 'FREEMIUM', 1, NULL, 'cat-13', NULL, NULL, 1777150116019, 1777150116019), ('t-89', 'notion-calendar', 'Notion Calendar', 'Notion Calendar is a native calendar client that pulls Google, Apple, and Zoom accounts into one view and layers Notion database deadlines on top. The menu bar shows the next meeting, command shortcuts handle the heavy lifting, and shared availability links and time zone overlays remove the usual scheduling friction. Used by VC firms running the stack in Notion to see pipeline deadlines, IC dates, and portfolio reviews alongside the live calendar.', 'Calendar app that unifies Google, Apple, and Zoom with Notion database events', '["See Notion pipeline deadlines and portfolio review dates alongside live Google or Outlook meetings","Share availability links and booking slots for founder meetings without leaving the calendar app"]', 'https://calendar.notion.so', 'https://www.google.com/s2/favicons?domain=calendar.notion.so&sz=128', 'FREEMIUM', 0, NULL, 'cat-13', NULL, NULL, 1777150116019, 1777150116019), ('t-90', 'vimcal', 'Vimcal', 'Vimcal is a keyboard-first calendar built for people who run dense schedules. Sub-100ms shortcuts, natural-language event creation, and time-zone overlap views cut the friction out of coordinating across regions. Focus mode, attendee profiles, and a dedicated EA surface round it out. Widely used by VC firms and their assistants to triage hundreds of weekly requests across founder calls, board meetings, and LP dinners without the calendar becoming the bottleneck.', 'Keyboard-first calendar built for heavy schedules, time zones, and EA workflows', '["Book cross-timezone founder and LP calls instantly by typing in natural language instead of dragging slots","Hand EAs a dedicated workflow to manage partner schedules, travel blocks, and board meeting chains"]', 'https://vimcal.com', 'https://www.google.com/s2/favicons?domain=vimcal.com&sz=128', 'PAID', 0, NULL, 'cat-13', NULL, NULL, 1777150116019, 1777150116019), ('t-91', 'circleback', 'Circleback', 'Circleback is an AI meeting assistant for Zoom, Google Meet, Teams, Slack huddles, and in-person conversations. It produces accurate transcripts in 100+ languages, structured notes, and assigned action items, then runs workflows into Gmail, Slack, HubSpot, Salesforce, Notion, and Zapier. Used by VC firms to keep partner meetings and founder calls searchable without manual writeups.', 'AI meeting notetaker that writes structured notes, action items, and automations', '["Auto-capture founder call notes and push action items into HubSpot or Notion","Search every past meeting for what a portfolio CEO said about hiring or runway"]', 'https://circleback.ai', 'https://www.google.com/s2/favicons?domain=circleback.ai&sz=128', 'PAID', 0, NULL, 'cat-14', NULL, NULL, 1777150116019, 1777150116019), ('t-92', 'fathom', 'Fathom', 'Fathom records Zoom, Google Meet, and Microsoft Teams calls, then delivers AI summaries, action items, and searchable transcripts within minutes of hanging up. A new desktop app captures without a visible bot, and meeting data pipes into Slack, Salesforce, HubSpot, Asana, and Notion. Used by VC firms to keep founder calls present rather than pecking notes on screen.', 'AI notetaker that summarises calls and syncs to Slack, HubSpot, and Salesforce', '["Stay present on founder pitches and get a clean memo-ready summary after the call","Sync call notes and action items into HubSpot or Affinity without copy-paste"]', 'https://fathom.ai', 'https://www.google.com/s2/favicons?domain=fathom.ai&sz=128', 'FREEMIUM', 1, NULL, 'cat-14', NULL, NULL, 1777150116019, 1777150116019), ('t-93', 'fireflies', 'Fireflies', 'Fireflies.ai transcribes, summarises, and analyses meetings across Zoom, Google Meet, Teams, and uploaded recordings, with speaker recognition in 100+ languages. AskFred answers questions across the meeting library, and Fireflies auto-populates CRMs and task tools through 200+ integrations. Used by VC firms to build a searchable memory of every founder call and partner discussion.', 'Meeting transcription and AI assistant with searchable archive across 200+ apps', '["Transcribe a pitch call and ask AskFred what the founder said about metrics","Auto-log meeting summaries, action items, and next steps into Salesforce, HubSpot, or Affinity"]', 'https://fireflies.ai', 'https://www.google.com/s2/favicons?domain=fireflies.ai&sz=128', 'FREEMIUM', 0, NULL, 'cat-14', NULL, NULL, 1777150116019, 1777150116019), ('t-94', 'granola', 'Granola', 'Granola is an AI notepad that transcribes your computer''s audio without sending a bot into Zoom, Meet, Teams, or Webex. You type sparse notes during the call the way you would in Apple Notes, and after it ends Granola enhances them into structured writeups using the full transcript. Templates, chat-with-transcript, and one-click export to Slack, Notion, and CRMs make it a favourite of VC investors taking back-to-back founder calls.', 'Meeting notepad that listens locally and enhances the notes you type', '["Take quick notes during a founder pitch and get a clean structured writeup after","Run custom templates for first-meeting notes, founder deep dives, and portfolio check-ins"]', 'https://granola.so', 'https://www.google.com/s2/favicons?domain=granola.so&sz=128', 'PAID', 1, NULL, 'cat-14', NULL, NULL, 1777150116019, 1777150116019), ('t-96', 'otter', 'Otter', 'Otter.ai is a veteran of AI transcription, generating real-time transcripts, speaker-labelled notes, and auto-summaries for Zoom, Google Meet, and Teams. OtterPilot joins calls, captures action items, and syncs with Salesforce, HubSpot, Slack, and Notion. Its AI Chat answers questions across every past meeting. Used by VC firms for founder calls, partner meetings, and long-form interview diligence.', 'Transcription and meeting notes with real-time capture and AI chat over history', '["Transcribe and summarise founder pitches with speaker-labelled notes, timestamps, and action items","Query the meeting library for what a specific founder or expert said on a topic"]', 'https://otter.ai', 'https://www.google.com/s2/favicons?domain=otter.ai&sz=128', 'FREEMIUM', 0, NULL, 'cat-14', NULL, NULL, 1777150116019, 1777150116019), ('t-97', 'aqua-voice', 'Aqua Voice', 'Aqua Voice is a desktop dictation tool for Mac and Windows built on its Avalon transcription model. It watches on-screen context to format output correctly, learns custom vocabulary for names and technical terms, and adapts tone between Slack, email, and docs across 49 languages. Used by VC investors to draft memo notes, Slack messages, and founder replies at speaking speed rather than typing.', 'Dictation app that turns speech into polished text across any Mac or Windows app', '["Dictate first-draft memo notes straight into Notion or Google Docs after a call","Fire off long Slack replies and founder emails without touching the keyboard"]', 'https://aquavoice.com', 'https://www.google.com/s2/favicons?domain=aquavoice.com&sz=128', 'PAID', 0, NULL, 'cat-15', NULL, NULL, 1777150116019, 1777150116019), ('t-98', 'superwhisper', 'Superwhisper', 'Superwhisper turns voice into polished text inside any app on macOS, Windows, or iOS. It runs offline, handles 100+ languages, and routes transcripts through GPT, Claude, or Llama for tone and format modes tuned to voice notes, Slack, or email. Push-to-talk and meeting recording round it out. Used by VC investors and founders who write faster by talking than typing.', 'Voice-to-text for Mac, Windows, iOS with offline mode and LLM post-processing', '["Dictate deal notes, founder emails, and Slack messages offline with custom vocabulary","Run voice transcripts through Claude or GPT for clean rewrites before sending"]', 'https://superwhisper.ai', 'https://www.google.com/s2/favicons?domain=superwhisper.ai&sz=128', 'PAID', 0, NULL, 'cat-15', NULL, NULL, 1777150116019, 1777150116019), ('t-99', 'willow-voice', 'Willow Voice', 'Willow Voice is a hotkey dictation app for Mac, Windows, and iPhone. Press the shortcut, talk, and it produces edited text with correct punctuation, names, and formatting across any app. AI mode turns short phrases into full messages, and style matching adapts tone per app. SOC 2 and HIPAA certified. Used by VC investors to draft emails, memos, and Slack messages by voice.', 'Hotkey dictation that cleans filler, matches your style, spells names right', '["Dictate structured follow-up emails to founders with names and terms spelled correctly","Draft first-pass memo sections by voice and edit the text rather than the transcript"]', 'https://willowvoice.com', 'https://www.google.com/s2/favicons?domain=willowvoice.com&sz=128', 'PAID', 0, NULL, 'cat-15', NULL, NULL, 1777150116019, 1777150116019), ('t-100', 'wispr-flow', 'Wispr Flow', 'Wispr Flow is a voice-first input method for Mac, Windows, iPhone, and Android. It transcribes speech, strips filler, corrects errors, and rewrites rambled thoughts into structured prose inside Gmail, Slack, Notion, VS Code, and 40+ other apps. A personal dictionary and snippet library cover names, scheduling links, and templates. Used by VC investors writing memos, emails, and pipeline notes by voice.', 'AI dictation that edits rambled speech into clean writing across any app', '["Speak rambling thoughts and get publishable memo paragraphs written directly in Notion","Trigger voice snippets for scheduling links, firm disclaimers, and common founder replies"]', 'https://wisprflow.com', 'https://www.google.com/s2/favicons?domain=wisprflow.com&sz=128', 'PAID', 1, NULL, 'cat-15', NULL, NULL, 1777150116019, 1777150116019), ('t-102', 'coda', 'Coda', 'Coda is a workspace that combines docs, tables, and applications in one surface. Teams build hubs, trackers, and internal tools with formulas, buttons, and automations, while Coda AI writes content and automates columns at scale. 600+ integrations span Calendar, Slack, Figma, and Jira. Used by VC firms to build pipeline trackers, portfolio dashboards, and LP update drafts that would otherwise live across five tools.', 'Docs-meet-databases workspace with formulas, automations, and 600+ integrations', '["Build a dealflow tracker with owner views, stage automations, and synced Slack updates","Run portfolio KPI dashboards pulling data from Airtable, Notion, and Google Sheets"]', 'https://coda.io', 'https://www.google.com/s2/favicons?domain=coda.io&sz=128', 'FREEMIUM', 0, NULL, 'cat-16', NULL, NULL, 1777150116019, 1777150116019), ('t-103', 'google-sheets', 'Google Sheets', 'Google Sheets is the cloud spreadsheet inside Google Workspace. Multiple people edit at once with version history, granular sharing, and comments. Gemini writes formulas, builds tables, and analyses data on request, and smart chips pull in files, people, and dates from Drive. Used by VC firms for every model, cap-table snapshot, LP list, and portfolio tracker that demands more flex than a purpose-built CRM.', 'Collaborative cloud spreadsheet with real-time editing and Gemini AI assistance', '["Build fund models, pipeline trackers, and portfolio KPI sheets shared live with the team","Use Gemini to generate formulas and summarise data without writing spreadsheet syntax"]', 'https://google.com', 'https://www.google.com/s2/favicons?domain=google.com&sz=128', 'FREE', 1, NULL, 'cat-16', NULL, NULL, 1777150116019, 1777150116019), ('t-105', 'bolt', 'Bolt', 'Bolt.new turns a prompt or Figma import into a running web app. The agent writes the code, hooks up databases and authentication, and deploys to a custom domain with analytics in one flow. Design system templates from Shadcn, Chakra, Material UI, and others keep outputs presentable. Used by VC investors to spin up portfolio-facing microsites, landing pages, and internal tools without engineering time.', 'Prompt-to-app builder that ships hosted web apps with databases and auth', '["Prototype a thesis microsite or founder-facing landing page from a single prompt","Build lightweight internal tools for the fund without pulling in an engineer"]', 'https://bolt.new', 'https://www.google.com/s2/favicons?domain=bolt.new&sz=128', 'FREEMIUM', 0, NULL, 'cat-17', NULL, NULL, 1777150116019, 1777150116019), ('t-106', 'emergent', 'Emergent', 'Emergent is a vibe-coding platform that turns natural language into production web and mobile apps, handling code, design, and deploy. Builders describe a product, and the agent ships it with LLM integrations, custom agents, and GitHub export on higher tiers. Used by VC investors to spin up internal tools, portfolio pages, and founder-facing prototypes without writing code or briefing engineers.', 'Natural-language builder for web and mobile apps with deployment and AI agents', '["Build an internal pipeline dashboard or portfolio portal from a plain-English spec","Ship a prototype of a thesis idea to share with founders before writing any code"]', 'https://emergent.sh', 'https://www.google.com/s2/favicons?domain=emergent.sh&sz=128', 'PAID', 0, NULL, 'cat-17', NULL, NULL, 1777150116019, 1777150116019), ('t-107', 'lovable', 'Lovable', 'Lovable builds web apps and sites from conversational prompts, screenshots, or reference docs. The AI generates a working prototype in real time, lets users iterate with follow-up instructions, and deploys in one click. It supports portfolios, SaaS products, and e-commerce. Used by VC investors and founders to test landing pages, internal tools, and MVPs without waiting on a development cycle.', 'AI app builder that turns a description or screenshot into a deployable web app', '["Prototype a founder idea or thesis microsite from a rough sketch in an afternoon","Build internal fund tools, portals, and dashboards without briefing an engineering team"]', 'https://lovable.dev', 'https://www.google.com/s2/favicons?domain=lovable.dev&sz=128', 'FREEMIUM', 1, NULL, 'cat-17', NULL, NULL, 1777150116019, 1777150116019), ('t-108', 'replit', 'Replit', 'Replit is a browser-based development environment paired with Agent 4, an AI that turns prompts into working full-stack apps. Hosting, authentication, databases, and monitoring are built in, and 100+ integrations cover OpenAI, Stripe, and Google Workspace. Parallel agents handle multi-task work at once. Used by VC investors and founders to ship prototypes, internal tools, and small products without a local dev setup.', 'Browser IDE and AI agent that builds and hosts full-stack apps from a prompt', '["Build and host an internal pipeline tool or founder directory from a plain prompt","Prototype thesis apps with working auth, database, and Stripe billing in one session"]', 'https://replit.com', 'https://www.google.com/s2/favicons?domain=replit.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-17', NULL, NULL, 1777150116019, 1777150116019), ('t-110', 'arc-browser', 'Arc', 'A Chromium-based browser from The Browser Company that replaces the tab strip with a vertical sidebar, Spaces for separating work and personal contexts, and split view for side-by-side research. Profiles keep firm logins cleanly apart from personal browsing. Used by VC firms where associates live in the browser all day and want dealflow, diligence, and portfolio tabs organised by context rather than collapsed into one wall of favicons.', 'Opinionated browser built around Spaces, profiles, and focused work', '["Separate dealflow, portfolio, and personal browsing into distinct Spaces with their own tabs and logins","Split-view two data rooms or a deck and a CRM side by side during fast diligence reads"]', 'https://arc.net', 'https://www.google.com/s2/favicons?domain=arc.net&sz=128', 'FREE', 0, NULL, 'cat-18', NULL, NULL, 1777150116019, 1777150116019), ('t-111', 'atlas-browser', 'Atlas', 'OpenAI''s browser that ships ChatGPT as a sidebar on every page, with cursor chat to rewrite selected text, browser memories that carry context across sessions, and an agent mode that can navigate sites and fill forms on the user''s behalf. Chromium-based, macOS first. Early uptake among VC firms using it to ask questions of pitch decks, earnings pages, and founder sites without copy-pasting into a separate ChatGPT tab.', 'OpenAI''s Chromium browser with ChatGPT and an agent mode built in', '["Ask ChatGPT questions directly against an open pitch deck, founder site, or data room page","Run agent mode to pull structured data from portfolio dashboards or competitor pages into a memo"]', 'https://chatgpt.com', 'https://www.google.com/s2/favicons?domain=chatgpt.com&sz=128', 'FREE', 0, NULL, 'cat-18', NULL, NULL, 1777150116019, 1777150116019), ('t-112', 'brave', 'Brave', 'A Chromium-based browser that blocks third-party ads, trackers, and fingerprinting by default, loading pages noticeably faster than stock Chrome. Brave Search offers an independent index, Leo AI answers questions from inside the tab, and an optional VPN encrypts connections device-wide. Chosen by VC teams who want a clean second browser for competitor research, reading founder sites, and any session where they''d rather not ship behavioural data back to ad networks.', 'Privacy-first Chromium browser with ad blocking and Leo AI built in', '["Browse founder sites and competitor pages without cookies, trackers, or fingerprinting following you around","Run Leo AI queries against articles and decks while keeping prompts out of ad-network logs"]', 'https://brave.com', 'https://www.google.com/s2/favicons?domain=brave.com&sz=128', 'FREE', 0, NULL, 'cat-18', NULL, NULL, 1777150116019, 1777150116019), ('t-113', 'comet', 'Comet', 'Perplexity''s Chromium-based browser with the company''s assistant built into the address bar and sidebar. It answers questions with live citations, summarises open pages, and runs agentic tasks like drafting emails, filling forms, and pulling data across tabs. Went free in late 2025. Adopted by VC teams that already use Perplexity for research and want that same reasoning layer to stay with them across data rooms, LinkedIn profiles, and news tabs.', 'Perplexity''s AI browser with an agent that can research and act on pages', '["Summarise and compare open founder pages or data room documents without leaving the browser","Delegate repetitive research, form-filling, or contact-pulling tasks across multiple tabs to the built-in assistant agent"]', 'https://perplexity.ai', 'https://www.google.com/s2/favicons?domain=perplexity.ai&sz=128', 'FREEMIUM', 0, NULL, 'cat-18', NULL, NULL, 1777150116019, 1777150116019), ('t-115', 'google-chrome', 'Google Chrome', 'The default browser for a large share of the working web, with profile sync, password manager, tab groups, and the Chrome Web Store ecosystem of extensions that almost every SaaS tool targets first. Gemini is integrated into the address bar for page-aware answers. Used by VC firms as the compatibility baseline where CRM extensions, LinkedIn scrapers, DocSend viewers, and deal-tracker plugins all just work without hunting for a Chromium equivalent.', 'The default browser for most of the web, now with Gemini built in', '["Run investor CRM, LinkedIn, and dealflow extensions against the broadest and most tested integration surface","Keep partner, associate, and personal profiles synced across laptop, phone, and backup machines"]', 'https://chrome.google.com', 'https://www.google.com/s2/favicons?domain=chrome.google.com&sz=128', 'FREE', 0, NULL, 'cat-18', NULL, NULL, 1777150116019, 1777150116019), ('t-65', 'carta', 'Carta', 'The incumbent platform for private-company equity, covering cap tables, 409A valuations, option grants, and secondary transactions, with a growing fund administration arm that handles capital calls, distributions, and LP reporting. Investors see portfolio ownership data flow straight from the companies they back. Used by VC firms both as the fund admin system of record and as the read-only view into cap tables at every Carta-hosted portfolio company they''ve invested in.', 'Cap table, 409A, and fund admin software for private markets', '["Run fund administration, capital calls, distributions, and LP statements from a single system of record","Track ownership, dilution, and option pool changes across every Carta-hosted portfolio company"]', 'https://carta.com', 'https://www.google.com/s2/favicons?domain=carta.com&sz=128', 'ENTERPRISE', 1, NULL, 'cat-19', '["portfolio-management"]', NULL, 1777150116019, 1777150116019), ('t-117', 'bardeen', 'Bardeen', 'A workflow automation platform where AI agents run recurring GTM tasks: scraping LinkedIn and company sites, enriching contacts with validated emails and phones, qualifying leads against a described ICP, and pushing results into Sheets, Airtable, Notion, or a CRM. Templates cover most common flows. Used by VC platform and associate teams to pull structured data on founder universes, track competitor hiring, and keep dealflow trackers fed without manual copy-paste.', 'No-code AI agents that scrape, enrich, and route data between tools', '["Scrape LinkedIn searches or company lists and enrich each row with emails and firmographic fields","Auto-sync meeting notes, founder contacts, or competitor signals from sources into Airtable or Notion"]', 'https://bardeen.ai', 'https://www.google.com/s2/favicons?domain=bardeen.ai&sz=128', 'FREEMIUM', 0, NULL, 'cat-19', NULL, NULL, 1777150116019, 1777150116019) ON CONFLICT(id) DO UPDATE SET slug = excluded.slug, name = excluded.name, description = excluded.description, short_desc = excluded.short_desc, use_cases = excluded.use_cases, website_url = excluded.website_url, logo_url = excluded.logo_url, pricing_model = excluded.pricing_model, is_featured = excluded.is_featured, featured_order = excluded.featured_order, category_id = excluded.category_id, extra_category_slugs = excluded.extra_category_slugs, archived_at = excluded.archived_at, updated_at = excluded.updated_at;
INSERT INTO tools (id, slug, name, description, short_desc, use_cases, website_url, logo_url, pricing_model, is_featured, featured_order, category_id, extra_category_slugs, archived_at, created_at, updated_at) VALUES ('t-118', 'canva', 'Canva', 'The default design tool for teams without a designer, with templates for decks, social posts, one-pagers, event collateral, and print, plus AI generation for images, copy, and layouts. Brand kits lock fonts, colours, and logos across a team. Used by VC firms to produce LP update decks, portfolio announcement graphics, event flyers, and the steady drip of social content that marketing does not want to route through a freelance designer every time.', 'Drag-and-drop design platform for decks, social, and marketing assets', '["Build LP update decks, event flyers, and portfolio announcement graphics from on-brand templates","Let non-designers on the platform team ship social posts and one-pagers in minutes instead of days"]', 'https://canva.com', 'https://www.google.com/s2/favicons?domain=canva.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-19', NULL, NULL, 1777150116019, 1777150116019), ('t-119', 'chronicle-hq', 'Chronicle HQ', 'A presentation tool that turns notes, outlines, or existing docs into slides built from layouts designed by people who came from Apple, McKinsey, and BCG. Brand guidelines enforce fonts, colours, and visual rules across every deck, and exports go to PPT, PDF, or web. Used by VC firms that want external decks, LP updates, and market maps to land at a visual bar higher than Google Slides without routing every request through a design hire.', 'AI presentation builder with designer-grade layouts and brand guardrails', '["Turn a rough market map or thesis doc into an on-brand LP or external deck in one sitting","Enforce firm brand across partner, associate, and platform decks without manual template policing"]', 'https://chroniclehq.com', 'https://www.google.com/s2/favicons?domain=chroniclehq.com&sz=128', 'PAID', 0, NULL, 'cat-19', NULL, NULL, 1777150116019, 1777150116019), ('t-120', 'circle', 'Circle', 'A community platform that bundles discussion spaces, live events, courses, paid memberships, branded iOS and Android apps, email broadcasts, and AI agents trained on community content. Creators and operators run the whole member experience from one place instead of stitching Slack, Teachable, and Stripe together. Used by VC firms to host founder communities, LP knowledge hubs, and platform programmes where threaded discussion and gated content matter more than real-time chat.', 'Branded community platform with spaces, courses, events, and payments', '["Host a founder or operator community with spaces, events, and gated content behind a firm-branded app","Run a paid LP or limited-partner programme with memberships, courses, and private discussion rooms"]', 'https://circle.so', 'https://www.google.com/s2/favicons?domain=circle.so&sz=128', 'PAID', 0, NULL, 'cat-19', NULL, NULL, 1777150116019, 1777150116019), ('t-122', 'docsend', 'DocSend', 'A document sharing service that replaces PDF attachments with trackable links, surfacing who opened a deck, which pages they lingered on, how long they spent, and whether they forwarded it. Access can be gated by email, expiration, or NDA. Used on both sides of the VC table: founders track which investors actually read the deck, and investors route sensitive memos, data rooms, and LP materials through DocSend to see exactly how they were consumed.', 'Secure document sharing with page-by-page analytics for decks and memos', '["Send pitch decks or LP memos as tracked links and see page-level engagement per recipient","Gate data rooms with email verification, NDAs, and expiry instead of shipping raw PDFs"]', 'https://docsend.com', 'https://www.google.com/s2/favicons?domain=docsend.com&sz=128', 'PAID', 1, NULL, 'cat-19', NULL, NULL, 1777150116019, 1777150116019), ('t-123', 'exa', 'Exa', 'A web search API designed for LLMs rather than humans, with specialised indexes for people, companies, code docs, financial data, and news, plus structured output schemas and highlight extraction that cuts token costs. Sub-180ms latency, SOC 2 Type II, zero data retention. Used by VC teams and the tools they build on top to power founder discovery, competitor mapping, and diligence agents that need clean, citation-backed retrieval instead of scraped Google results.', 'Neural search API built for AI agents and structured research workflows', '["Power internal founder-discovery or competitor-mapping agents with structured, citation-backed search over news and company pages","Enrich dealflow records by extracting named entities and highlights from company and news pages"]', 'https://exa.ai', 'https://www.google.com/s2/favicons?domain=exa.ai&sz=128', 'PAID', 0, NULL, 'cat-19', NULL, NULL, 1777150116019, 1777150116019), ('t-124', 'gamma', 'Gamma', 'An AI tool that turns a prompt, outline, or pasted doc into a polished deck, written document, or one-page website in a responsive card format that adapts to any screen. Built-in templates, charts, and image generation cover most business content needs. Used by VC firms to rough out thesis decks, LP updates, market maps, and event microsites in the time it used to take to open a PowerPoint template and align the first text box.', 'AI generator for decks, documents, and webpages from a single prompt', '["Draft thesis decks, market maps, or LP updates from a prompt or existing memo in minutes","Spin up a lightweight event page or portfolio microsite without a designer or web build"]', 'https://gamma.app', 'https://www.google.com/s2/favicons?domain=gamma.app&sz=128', 'FREEMIUM', 0, NULL, 'cat-19', NULL, NULL, 1777150116019, 1777150116019), ('t-125', 'getro', 'Getro', 'Getro powers branded job boards and talent networks for investor communities, aggregating open roles across portfolio companies and matching candidates to founders who are hiring. The platform tracks intros, applicants, and successful hires with reporting on network ROI. Used by VC firms to run a portfolio jobs hub, surface warm candidate intros, and prove the value of platform work to LPs and founders.', 'Branded job boards and talent networks built for VC platform teams', '["Run a branded jobs board that aggregates every open role across the portfolio automatically","Make warm candidate introductions at scale and track which hires actually close"]', 'https://getro.com', 'https://www.google.com/s2/favicons?domain=getro.com&sz=128', 'PAID', 0, NULL, 'cat-19', NULL, NULL, 1777150116019, 1777150116019), ('t-126', 'gumloop', 'Gumloop', 'Gumloop is a visual canvas for building AI agents that connect LLMs to tools like Slack, HubSpot, Salesforce, and internal databases. Teams drag nodes to define multi-step workflows, schedule recurring runs, and trigger agents from chat. Multi-model support keeps the firm off a single vendor. Used by VC firms to automate deck summarisation, inbound deal triage, and portfolio data pulls without writing code.', 'No-code AI automation platform for building and running agent workflows', '["Automate inbound deal triage by scoring decks and routing them to the right partner","Build a recurring agent that monitors portfolio company news and flags material signals"]', 'https://gumloop.com', 'https://www.google.com/s2/favicons?domain=gumloop.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-19', NULL, NULL, 1777150116019, 1777150116019), ('t-127', 'icypeas', 'Icypeas', 'Icypeas finds work email addresses from a name and company, verifies deliverability including catch-all domains, and runs reverse lookups that map an email to a LinkedIn profile. The database refreshes monthly against one billion records and the API plugs into outreach tools. Used by VC firms to enrich founder lists, find warm contacts inside a target company, and keep CRM records clean before a campaign.', 'Email finder and verifier that turns names or domains into verified contacts', '["Enrich a sourcing list with verified founder emails before a cold outbound campaign","Reverse-lookup an unknown email from inbound traffic to identify the sender and company"]', 'https://icypeas.com', 'https://www.google.com/s2/favicons?domain=icypeas.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-19', NULL, NULL, 1777150116019, 1777150116019), ('t-128', 'luma', 'Luma', 'Luma turns an event into a single shareable page: guests RSVP, get email and SMS reminders, and check in on arrival. Hosts manage the guest list, sell tickets, and message attendees from one dashboard. Around two million people sign up through Luma every month. Widely used by VC firms to run founder dinners, demo days, LP mixers, and office hours without stitching together Mailchimp, Eventbrite, and a spreadsheet.', 'Event pages with invites, RSVPs, ticketing, and check-in in one link', '["Host a founder dinner with invites, RSVPs, waitlist, and check-in from one event page","Run a demo day or LP mixer with ticketing, reminders, and a shared attendee directory"]', 'https://lu.ma', 'https://www.google.com/s2/favicons?domain=lu.ma&sz=128', 'FREEMIUM', 0, NULL, 'cat-19', NULL, NULL, 1777150116019, 1777150116019), ('t-129', 'mailchimp', 'Mailchimp', 'Mailchimp is an email and SMS marketing platform with a drag-and-drop designer, audience segmentation, automation flows, and analytics that tie campaigns back to revenue. Integrations cover Shopify, Stripe, and a long tail of CRMs. Owned by Intuit and used by millions of small and mid-market teams. Used by VC firms to send LP letters, founder newsletters, and portfolio update digests with tracking on who actually opened the email.', 'Email and SMS marketing platform with automation and audience segmentation', '["Send quarterly LP letters and portfolio updates with open, click, and engagement tracking","Run a founder newsletter that segments recipients by sector, stage, or relationship warmth"]', 'https://mailchimp.com', 'https://www.google.com/s2/favicons?domain=mailchimp.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-19', NULL, NULL, 1777150116019, 1777150116019), ('t-130', 'medium', 'Medium', 'Medium is a publishing platform where writers post essays and longer pieces into a shared discovery feed rather than a private blog. Topic-based publications, recommendations, and a paid membership give stories reach without the owner running SEO or a newsletter list. The editor handles formatting and images cleanly. Used by VC firms and partners to publish thesis pieces, market maps, and portfolio announcements that surface to a wider founder and operator audience.', 'Publishing platform for long-form essays with built-in reader distribution', '["Publish a sector thesis or market map that reaches founders through Medium''s discovery feed","Run a firm publication where every partner posts memos, playbooks, and portfolio stories"]', 'https://medium.com', 'https://www.google.com/s2/favicons?domain=medium.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-19', NULL, NULL, 1777150116019, 1777150116019), ('t-131', 'raycast', 'Raycast', 'Raycast is a keyboard launcher that replaces Spotlight with AI, snippets, window management, and a library of over a thousand extensions covering Slack, Notion, Linear, GitHub, and most SaaS tools. Quick AI answers sit behind a hotkey, so drafting and lookup happen without switching apps. Used by VC firms for fast CRM search, quick AI drafts during a call, and snippets that paste the firm''s template replies into email.', 'Keyboard-first Mac launcher with AI, snippets, and a deep extension library', '["Search Affinity, Notion, and Slack from a single hotkey without opening each app","Fire a Quick AI prompt mid-meeting to draft a memo section or summarise a decision"]', 'https://raycast.com', 'https://www.google.com/s2/favicons?domain=raycast.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-19', NULL, NULL, 1777150116019, 1777150116019), ('t-132', 'substack', 'Substack', 'Substack is a publishing platform that combines email newsletters, podcasts, and a native app feed with paid subscriptions and reader discussions. Writers keep the subscriber list, Substack handles payments, hosting, and recommendations that grow the list from other newsletters. Widely used by VC investors to run a thesis newsletter, build reputation with founders, and sometimes monetise a paid tier that funds the research behind it.', 'Newsletter platform with paid subscriptions, podcasts, and reader discussion', '["Run a public thesis newsletter that compounds inbound dealflow from founders who subscribe","Publish interviews and market notes to a paid tier that funds the research underneath"]', 'https://substack.com', 'https://www.google.com/s2/favicons?domain=substack.com&sz=128', 'FREEMIUM', 1, NULL, 'cat-19', NULL, NULL, 1777150116019, 1777150116019), ('t-133', 'tally', 'Tally', 'Tally is a form builder where you type fields into a document rather than dragging them onto a canvas, and every core feature including unlimited forms and submissions is free. Conditional logic, calculations, file uploads, e-signatures, and Stripe payments are built in, with integrations for Notion, Google Sheets, Airtable, and Slack. Used by VC firms for inbound deal intake forms, founder feedback surveys, and event RSVPs that pipe into the dealflow database.', 'Free form builder with conditional logic, payments, and Notion-style editing', '["Collect inbound decks through a branded intake form that writes directly into Notion or Airtable","Run a quick portfolio founder survey with conditional questions and responses routed to Slack"]', 'https://tally.so', 'https://www.google.com/s2/favicons?domain=tally.so&sz=128', 'FREEMIUM', 0, NULL, 'cat-19', NULL, NULL, 1777150116019, 1777150116019), ('t-135', 'typeform', 'Typeform', 'Typeform builds forms that ask one question at a time with a conversational feel, driving higher completion rates than traditional grid surveys. AI helps generate the form from a prompt, and integrations cover Slack, HubSpot, Mailchimp, and hundreds more. Interactive video and logic jumps let responses branch in real time. Used by VC firms for founder intake, LP surveys, and event feedback where completion quality matters more than raw field count.', 'Conversational forms with AI-assisted building and interactive design', '["Build a branded founder intake form that feels like a conversation rather than a grid","Run an LP survey with logic jumps that route questions based on fund size and geography"]', 'https://typeform.com', 'https://www.google.com/s2/favicons?domain=typeform.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-19', NULL, NULL, 1777150116019, 1777150116019), ('t-136', 'webflow', 'Webflow', 'Webflow is a visual development platform for production websites, combining a designer that outputs clean HTML and CSS, a CMS for dynamic content, managed hosting with a global CDN, and AI tools for SEO and personalisation. Teams ship without a frontend engineer while keeping pixel control. Used by VC firms to run the public fund site, portfolio company pages, and thesis microsites without waiting for an agency each time copy changes.', 'Visual website builder with CMS, hosting, and AI optimisation built in', '["Ship and maintain the fund website and portfolio page without a developer in the loop","Spin up a thesis microsite or event landing page with a CMS the whole team can edit"]', 'https://webflow.com', 'https://www.google.com/s2/favicons?domain=webflow.com&sz=128', 'FREEMIUM', 0, NULL, 'cat-19', NULL, NULL, 1777150116019, 1777150116019), ('t-137', 'wizikey', 'Wizikey', 'Wizikey is a media monitoring platform that tracks brand, competitor, and industry mentions across online, print, broadcast, and social in one dashboard, with sentiment analysis, real-time alerts, and coverage benchmarking. AI assists storytelling and reporting for PR teams. Used by VC firms and their portfolio comms teams to watch founder and portfolio coverage, benchmark share of voice against rivals, and catch negative press before it reaches the partner meeting.', 'AI media monitoring across online, print, broadcast, and social channels', '["Monitor press coverage across the portfolio and alert the team on negative sentiment spikes","Benchmark a portfolio company''s share of voice against named competitors each quarter"]', 'https://wizikey.com', 'https://www.google.com/s2/favicons?domain=wizikey.com&sz=128', 'PAID', 0, NULL, 'cat-19', NULL, NULL, 1777150116019, 1777150116019), ('t-138', 'zoom', 'Zoom', 'Zoom is the default video meeting tool for most firms, now a wider workplace platform with chat, phone, webinars, docs, and AI Companion that summarises meetings and drafts follow-ups. Recordings, transcripts, and whiteboards persist after the call. Used by VC firms for founder pitches, partner meetings, and LP calls, with AI-generated notes feeding back into the CRM so every conversation leaves a durable, searchable record.', 'Video meetings, webinars, and AI note-taking on a unified comms platform', '["Run founder pitches and partner meetings with AI summaries auto-filed to the CRM","Host an LP update webinar with registration, recording, and a searchable transcript afterwards"]', 'https://zoom.us', 'https://www.google.com/s2/favicons?domain=zoom.us&sz=128', 'FREEMIUM', 1, NULL, 'cat-19', NULL, NULL, 1777150116019, 1777150116019) ON CONFLICT(id) DO UPDATE SET slug = excluded.slug, name = excluded.name, description = excluded.description, short_desc = excluded.short_desc, use_cases = excluded.use_cases, website_url = excluded.website_url, logo_url = excluded.logo_url, pricing_model = excluded.pricing_model, is_featured = excluded.is_featured, featured_order = excluded.featured_order, category_id = excluded.category_id, extra_category_slugs = excluded.extra_category_slugs, archived_at = excluded.archived_at, updated_at = excluded.updated_at;

